def execute(params):
    """Create a new file with specified content."""
    import os

    file_path = params.get('filePath')
    if not file_path:
        return {'success': False, 'error': 'filePath parameter is required'}

    content = params.get('content', '')
    dir_path = os.path.dirname(file_path)
    if dir_path:
        os.makedirs(dir_path, exist_ok=True)

    with open(file_path, 'w') as f:
        f.write(content)

    return {
        'success': True,
        'message': f'File created: {file_path}',
        'filePath': file_path,
        'size': len(content)
    }

def execute(params):
    """Read contents of a file with chunking support."""
    import os
    file_path = params.get('filePath')
    start_line = params.get('startLine')
    end_line = params.get('endLine')
    chunk_index = params.get('chunkIndex')
    chunk_size = params.get('chunkSize', 500)
    max_chars = 100000

    if not file_path:
        return {'success': False, 'error': 'filePath parameter is required'}

    try:
        # Binary / archive sniff. Opening a tarball or any binary as utf-8
        # fails with a cryptic codec error; detect common archive magics
        # FIRST and point the model at the right extractor. FileNotFoundError
        # falls through to the existing handler below.
        with open(file_path, 'rb') as _bf:
            head = _bf.read(4096)
        tar_marker = head[257:262] if len(head) >= 262 else b''
        arch_kind = None
        if head[:2] == b'\x1f\x8b':
            arch_kind = 'gzip (.gz/.tgz/.tar.gz)'
        elif head[:4] in (b'PK\x03\x04', b'PK\x05\x06'):
            arch_kind = 'zip (.zip)'
        elif head[:6] == b'7z\xbc\xaf\x27\x1c':
            arch_kind = '7-Zip (.7z)'
        elif head[:4] == b'Rar!':
            arch_kind = 'rar (.rar)'
        elif head[:6] == b'\xfd7zXZ\x00':
            arch_kind = 'xz (.xz/.tar.xz)'
        elif head[:3] == b'BZh':
            arch_kind = 'bzip2 (.bz2/.tar.bz2)'
        elif tar_marker == b'ustar':
            arch_kind = 'tar (.tar)'
        if arch_kind:
            return {'success': False, 'error': f'{file_path} is a binary archive ({arch_kind}); read_file expects text. Use extract_archive (preferred when the user uploaded the archive via chat - pass the archiveId from the [Archive uploaded:...] marker). Otherwise: tar_extract for .tar/.tar.gz/.tgz/.tar.bz2/.tar.xz, unzip_file for .zip.'}
        if b'\x00' in head:
            return {'success': False, 'error': f'{file_path} looks like a binary file (NUL bytes in first 4KB). read_file only handles text; use run_python with binary-mode open for arbitrary binaries, transform_image for images, or read_xlsx for spreadsheets.'}

        with open(file_path, 'r') as f:
            lines = f.readlines()
        total_lines = len(lines)
        total_chars = sum(len(l) for l in lines)
        estimated_tokens = total_chars // 4

        if start_line is not None or end_line is not None:
            start = max(0, (start_line or 1) - 1)
            end = min(total_lines, end_line or total_lines)
            selected = lines[start:end]
            return {'success': True, 'filePath': file_path, 'content': ''.join(selected), 'lineRange': {'start': start+1, 'end': end}, 'totalLines': total_lines}

        if chunk_index is not None:
            total_chunks = (total_lines + chunk_size - 1) // chunk_size
            if chunk_index < 0 or chunk_index >= total_chunks:
                return {'success': False, 'error': f'Invalid chunkIndex. Valid: 0-{total_chunks-1}'}
            start = chunk_index * chunk_size
            end = min(start + chunk_size, total_lines)
            chunk_lines = lines[start:end]
            return {'success': True, 'filePath': file_path, 'content': ''.join(chunk_lines), 'chunkInfo': {'currentChunk': chunk_index, 'totalChunks': total_chunks, 'lineRange': {'start': start+1, 'end': end}}, 'totalLines': total_lines}

        if total_chars > max_chars:
            total_chunks = (total_lines + chunk_size - 1) // chunk_size
            preview = ''.join(lines[:50]) + ('\n... [truncated]' if total_lines > 50 else '')
            return {'success': True, 'filePath': file_path, 'warning': 'FILE_TOO_LARGE', 'message': f'File has {total_lines} lines (~{estimated_tokens} tokens). Use chunkIndex to read in parts.', 'preview': preview, 'fileInfo': {'totalLines': total_lines, 'totalChars': total_chars, 'totalChunks': total_chunks, 'chunkSize': chunk_size}}

        return {'success': True, 'content': ''.join(lines), 'filePath': file_path, 'totalLines': total_lines, 'totalChars': total_chars}
    except FileNotFoundError:
        # Locate likely matches under /workspace so the model can retry with the
        # actual path instead of guessing /tmp/... again. Match by basename, and
        # also by the trailing 1-2 path segments (e.g. "package/utils.js") to
        # disambiguate when many files share a name.
        candidates = []
        try:
            basename = os.path.basename(str(file_path))
            parts = [p for p in str(file_path).replace('\\', '/').split('/') if p]
            tail1 = '/'.join(parts[-1:]) if parts else ''
            tail2 = '/'.join(parts[-2:]) if len(parts) >= 2 else ''
            for root, dirs, filenames in os.walk('/workspace'):
                # Prune cache/git noise to keep the scan fast.
                dirs[:] = [d for d in dirs if d not in ('.git', 'node_modules', '__pycache__', '.venv')]
                for f in filenames:
                    if f != basename:
                        continue
                    full = os.path.join(root, f)
                    rel = os.path.relpath(full, '/workspace')
                    rel_posix = rel.replace(os.sep, '/')
                    score = 1
                    if tail2 and rel_posix.endswith(tail2):
                        score = 3
                    elif tail1 and rel_posix.endswith(tail1):
                        score = 2
                    candidates.append((score, rel_posix))
                    if len(candidates) >= 50:
                        break
                if len(candidates) >= 50:
                    break
            candidates.sort(key=lambda x: (-x[0], len(x[1])))
        except Exception:
            pass
        match_hint = ''
        if candidates:
            top = [c[1] for c in candidates[:5]]
            match_hint = ' Found ' + str(len(candidates)) + ' file(s) named \'' + os.path.basename(str(file_path)) + "' under /workspace; try one of: " + ', '.join(top) + '.'
        return {'success': False, 'error': 'File not found: ' + str(file_path) + '. (sandbox sees only /workspace; pass /workspace/<file> or a path relative to it)' + match_hint + ' If this file was uploaded via the chat UI in this turn or earlier in the conversation, it is at /workspace/uploads/<name>. Extracted archive contents live at /workspace/archives/<archiveId>/...; the extract_archive result lists each entry\'s workspace-relative path - use those verbatim, do NOT prepend /tmp/. The same content is also embedded inline in the === FILE N === blocks of the originating user message for immediate access without a tool call.'}
    except Exception as e:
        return {'success': False, 'error': str(e)}

def execute(params):
    """Update an existing file with new content."""
    file_path = params.get('filePath')
    if not file_path:
        return {'success': False, 'error': 'filePath parameter is required'}

    content = params.get('content', '')

    try:
        with open(file_path, 'w') as f:
            f.write(content)
        return {
            'success': True,
            'message': f'File updated: {file_path}',
            'filePath': file_path,
            'size': len(content)
        }
    except FileNotFoundError:
        return {'success': False, 'error': 'File or parent directory not found: ' + str(file_path) + '. (sandbox sees only /workspace; pass /workspace/<file> or a path relative to it)'}
    except IsADirectoryError:
        return {'success': False, 'error': 'Path is a directory, not a file: ' + str(file_path)}
    except PermissionError as e:
        return {'success': False, 'error': 'Permission denied writing ' + str(file_path) + ': ' + str(e)}
    except Exception as e:
        return {'success': False, 'error': str(e)}

def execute(params):
    """Delete a file from the filesystem."""
    import os

    file_path = params.get('filePath')
    if not file_path:
        return {'success': False, 'error': 'filePath parameter is required'}

    try:
        os.remove(file_path)
        return {
            'success': True,
            'message': f'File deleted: {file_path}'
        }
    except FileNotFoundError:
        return {'success': False, 'error': 'File not found: ' + str(file_path) + '. (sandbox sees only /workspace; pass /workspace/<file> or a path relative to it)'}
    except Exception as e:
        return {'success': False, 'error': str(e)}

def execute(params):
    """Delete a directory and all its contents recursively."""
    import shutil
    import os

    dir_path = params.get('dirPath')
    if not dir_path:
        return {'success': False, 'error': 'dirPath parameter is required'}

    try:
        if os.path.isfile(dir_path):
            return {'success': False, 'error': f'Path is a file, not a directory. Use delete_file instead: {dir_path}'}

        if not os.path.exists(dir_path):
            return {'success': False, 'error': 'Directory not found: ' + str(dir_path) + '. (sandbox sees only /workspace; pass /workspace/<file> or a path relative to it)'}

        shutil.rmtree(dir_path)
        return {
            'success': True,
            'message': f'Directory deleted: {dir_path}'
        }
    except Exception as e:
        return {'success': False, 'error': str(e)}

def execute(params):
    """List directory contents with optional recursion.

    Recursive mode excludes common noise dirs by default (.git,
    node_modules, __pycache__, .venv, venv, .next, dist, build,
    .cache, .nuxt, target, .gradle, .idea, .vscode, .pytest_cache,
    .mypy_cache, .ruff_cache, .tox, .eggs, .nyc_output, coverage).
    Pass includeNoise=True to see everything, or ignoreDirs=[] to
    disable filtering entirely. Custom ignoreDirs extends (not
    replaces) the default list.

    Returns structured entries with an absolute `path` so
    downstream skills (read_file, delete_file, ...) can
    consume them directly. `name` is the basename for display;
    `relPath` is the path relative to the dirPath argument for
    compact UI output.
    """
    import os

    dir_path = params.get('dirPath')
    if not dir_path:
        return {'success': False, 'error': 'dirPath parameter is required'}

    recursive = bool(params.get('recursive') or False)
    max_depth = int(params.get('maxDepth') or 8)
    max_entries = int(params.get('maxEntries') or 500)
    include_noise = bool(params.get('includeNoise') or False)
    extra_ignore = params.get('ignoreDirs') or []
    if not isinstance(extra_ignore, list):
        extra_ignore = []

    DEFAULT_NOISE = {
        '.git', 'node_modules', '__pycache__', '.venv', 'venv',
        '.next', 'dist', 'build', '.cache', '.nuxt', 'target',
        '.gradle', '.idea', '.vscode', '.pytest_cache',
        '.mypy_cache', '.ruff_cache', '.tox', '.eggs',
        '.nyc_output', 'coverage', '.DS_Store',
    }
    # For repos cloned by git_clone_shallow, never apply the default noise
    # filter — the user wants every file in the repo visible. Drop only `.git`
    # (pure git internals, not user content).
    abs_dir_for_check = os.path.abspath(dir_path) if dir_path else ''
    is_gh_clone = '/gh-clones/' in (abs_dir_for_check + '/')
    noise_set = set()
    if is_gh_clone:
        noise_set = {'.git'}
    elif not include_noise:
        noise_set = set(DEFAULT_NOISE)
    for x in extra_ignore:
        if isinstance(x, str) and x:
            noise_set.add(x)

    if not os.path.exists(dir_path):
        return {'success': False, 'error': f'Path does not exist: {dir_path}'}
    if not os.path.isdir(dir_path):
        return {'success': False, 'error': f'Path is not a directory: {dir_path}'}

    base = os.path.abspath(dir_path)
    entries = []
    truncated = False
    skipped_noise_dirs = 0

    def _stat_entry(full_path, name, rel_path):
        try:
            st = os.lstat(full_path)
            is_dir = os.path.isdir(full_path) and not os.path.islink(full_path)
            return {
                'name': name,
                'path': full_path,
                'relPath': rel_path,
                'type': 'dir' if is_dir else ('link' if os.path.islink(full_path) else 'file'),
                'size': int(st.st_size) if not is_dir else None,
                'modified': int(st.st_mtime),
            }
        except OSError as e:
            return {'name': name, 'path': full_path, 'relPath': rel_path, 'type': 'unknown', 'error': str(e)}

    if recursive:
        for root, dirs, filenames in os.walk(base):
            rel_root = os.path.relpath(root, base)
            depth = 0 if rel_root == '.' else rel_root.count(os.sep) + 1
            if depth > max_depth:
                dirs.clear()
                continue
            # Prune noise dirs in-place so os.walk doesn't descend into them.
            if noise_set:
                pruned = [d for d in dirs if d in noise_set]
                skipped_noise_dirs += len(pruned)
                dirs[:] = [d for d in dirs if d not in noise_set]
            for d in sorted(dirs):
                if len(entries) >= max_entries:
                    truncated = True
                    break
                full = os.path.join(root, d)
                rel = os.path.relpath(full, base)
                entries.append(_stat_entry(full, d, rel))
            if truncated:
                break
            for f in sorted(filenames):
                if len(entries) >= max_entries:
                    truncated = True
                    break
                if not include_noise and f in noise_set:
                    skipped_noise_dirs += 1
                    continue
                full = os.path.join(root, f)
                rel = os.path.relpath(full, base)
                entries.append(_stat_entry(full, f, rel))
            if truncated:
                break
    else:
        try:
            names = sorted(os.listdir(base))
        except OSError as e:
            return {'success': False, 'error': str(e)}
        for name in names:
            if not include_noise and name in noise_set:
                skipped_noise_dirs += 1
                continue
            if len(entries) >= max_entries:
                truncated = True
                break
            full = os.path.join(base, name)
            entries.append(_stat_entry(full, name, name))
        entries.sort(key=lambda e: (0 if e.get('type') == 'dir' else 1, e.get('name', '')))

    file_count = sum(1 for e in entries if e.get('type') == 'file')
    dir_count = sum(1 for e in entries if e.get('type') == 'dir')

    return {
        'success': True,
        'dirPath': base,
        'recursive': recursive,
        'count': len(entries),
        'fileCount': file_count,
        'dirCount': dir_count,
        'truncated': truncated,
        'skippedNoise': skipped_noise_dirs,
        'maxEntries': max_entries,
        'maxDepth': max_depth if recursive else None,
        'entries': entries,
    }

def execute(params):
    """Move or rename a file."""
    import shutil, os

    source_path = params.get('sourcePath')
    dest_path = params.get('destPath')

    if not source_path or not dest_path:
        return {'success': False, 'error': 'sourcePath and destPath parameters are required'}

    # Collision detection: the sandbox path normalizer rewrites absolute paths
    # outside /workspace to /workspace/<basename>. Two different host paths
    # like /a/foo.py and /b/foo.py both collapse to /workspace/foo.py, which
    # would silently turn into a self-move. Catch it explicitly so the model
    # gets a useful error instead of a SameFileError stack trace.
    if os.path.abspath(source_path) == os.path.abspath(dest_path):
        return {'success': False, 'error': 'sourcePath and destPath resolve to the same path (' + str(source_path) + '). (sandbox sees only /workspace; pass /workspace/<file> or a path relative to it)'}

    if not os.path.exists(source_path):
        return {'success': False, 'error': 'File not found: ' + str(source_path) + '. (sandbox sees only /workspace; pass /workspace/<file> or a path relative to it)'}

    try:
        shutil.move(source_path, dest_path)
        return {
            'success': True,
            'message': f'File moved: {source_path} -> {dest_path}'
        }
    except Exception as e:
        return {'success': False, 'error': str(e)}

def execute(params):
    """Copy a file to a new location."""
    import shutil, os

    source_path = params.get('sourcePath')
    dest_path = params.get('destPath')

    if not source_path or not dest_path:
        return {'success': False, 'error': 'sourcePath and destPath parameters are required'}

    # See move_file for the rationale on collision detection.
    if os.path.abspath(source_path) == os.path.abspath(dest_path):
        return {'success': False, 'error': 'sourcePath and destPath resolve to the same path (' + str(source_path) + '). (sandbox sees only /workspace; pass /workspace/<file> or a path relative to it)'}

    if not os.path.exists(source_path):
        return {'success': False, 'error': 'File not found: ' + str(source_path) + '. (sandbox sees only /workspace; pass /workspace/<file> or a path relative to it)'}

    try:
        shutil.copy2(source_path, dest_path)
        return {
            'success': True,
            'message': f'File copied: {source_path} -> {dest_path}'
        }
    except Exception as e:
        return {'success': False, 'error': str(e)}

def execute(params):
    """Copy a workspace file into /workspace/artifacts/ so the chat UI surfaces it as a download."""
    import os, re, shutil

    source_path = (params.get('sourcePath') or params.get('path') or params.get('file') or '').strip()
    if not source_path:
        return {'success': False, 'error': 'sourcePath parameter is required'}

    # Resolve relative paths against /workspace so the model can pass
    # bare filenames it generated in the same workspace.
    if not os.path.isabs(source_path):
        source_path = os.path.join('/workspace', source_path)

    if not os.path.isfile(source_path):
        return {'success': False, 'error': f'no such file: {source_path}'}

    raw_name = (params.get('filename') or os.path.basename(source_path) or 'download').strip()
    base = os.path.basename(raw_name) or 'download'
    # Match the artifact endpoint's filename guard: strip anything outside
    # [A-Za-z0-9._-], cap length, never start with a dot.
    base = re.sub(r'[^A-Za-z0-9._\-]', '_', base)[:120].lstrip('.') or 'download'

    artifacts_dir = '/workspace/artifacts'
    try:
        os.makedirs(artifacts_dir, exist_ok=True)
    except OSError as e:
        return {'success': False, 'error': f'failed to create /workspace/artifacts/: {e}'}

    dest_path = os.path.join(artifacts_dir, base)
    try:
        shutil.copyfile(source_path, dest_path)
        # Touch the mtime so the sandbox runner's mtime-filtered scan
        # picks it up even if the source file is older than this run.
        os.utime(dest_path, None)
    except Exception as e:
        return {'success': False, 'error': f'copy failed: {e}'}

    try:
        size = os.path.getsize(dest_path)
    except OSError:
        size = None

    return {
        'success': True,
        'filename': base,
        'path': dest_path,
        'size': size,
        'note': 'File copied into /workspace/artifacts/. The server attaches _artifacts metadata automatically — the chat UI renders a download chip on this tool result.',
    }

def execute(params):
    """Apply a Pillow transform to an image and write the result under /workspace/artifacts/."""
    import os, re
    try:
        from PIL import Image, ImageOps
    except ImportError:
        return {'success': False, 'error': 'Pillow not installed in the sandbox image'}

    src = (params.get('sourcePath') or params.get('path') or '').strip()
    if not src:
        return {'success': False, 'error': 'sourcePath is required'}
    if not os.path.isabs(src):
        src = os.path.join('/workspace', src)
    if not os.path.isfile(src):
        return {'success': False, 'error': f'no such file: {src}'}

    op = (params.get('operation') or '').strip().lower()
    if op not in ('resize', 'crop', 'thumbnail', 'rotate', 'convert', 'grayscale'):
        return {'success': False, 'error': "operation must be one of: resize, crop, thumbnail, rotate, convert, grayscale"}

    out_format = (params.get('format') or '').strip().lower() or None
    quality = int(params.get('quality') or 90)

    # Output filename — default into /workspace/artifacts/ so the chat UI
    # auto-surfaces the result as a download chip.
    raw_name = (params.get('outputName') or params.get('filename') or '').strip()
    if not raw_name:
        base = os.path.basename(src)
        stem, ext = os.path.splitext(base)
        suffix = '.' + (out_format or ext.lstrip('.') or 'png')
        raw_name = stem + '.' + op + suffix
    safe = re.sub(r'[^A-Za-z0-9._\-]', '_', os.path.basename(raw_name))[:120].lstrip('.') or 'output.png'
    out_dir = '/workspace/artifacts'
    os.makedirs(out_dir, exist_ok=True)
    out_path = os.path.join(out_dir, safe)

    try:
        img = Image.open(src)
        # Auto-rotate from EXIF so width/height in subsequent ops are intuitive.
        try: img = ImageOps.exif_transpose(img)
        except Exception: pass
        original_size = img.size

        if op == 'resize':
            w = params.get('width'); h = params.get('height')
            if not (w or h):
                return {'success': False, 'error': 'resize needs width and/or height'}
            if w and h:
                img = img.resize((int(w), int(h)), Image.LANCZOS)
            elif w:
                ratio = int(w) / img.width
                img = img.resize((int(w), max(1, int(img.height * ratio))), Image.LANCZOS)
            else:
                ratio = int(h) / img.height
                img = img.resize((max(1, int(img.width * ratio)), int(h)), Image.LANCZOS)
        elif op == 'thumbnail':
            mw = int(params.get('maxWidth') or params.get('width') or 256)
            mh = int(params.get('maxHeight') or params.get('height') or mw)
            img.thumbnail((mw, mh), Image.LANCZOS)
        elif op == 'crop':
            x = int(params.get('x') or 0); y = int(params.get('y') or 0)
            w = params.get('width'); h = params.get('height')
            if not (w and h):
                return {'success': False, 'error': 'crop needs width and height'}
            img = img.crop((x, y, x + int(w), y + int(h)))
        elif op == 'rotate':
            angle = float(params.get('angle') or 0)
            expand = bool(params.get('expand', True))
            img = img.rotate(angle, expand=expand, resample=Image.BICUBIC)
        elif op == 'grayscale':
            img = ImageOps.grayscale(img)
        # 'convert' is a no-op transform — only the output format changes.

        save_kwargs = {}
        save_format = (out_format or os.path.splitext(out_path)[1].lstrip('.') or 'png').upper()
        if save_format == 'JPG': save_format = 'JPEG'
        if save_format == 'JPEG':
            if img.mode in ('RGBA', 'P'):
                img = img.convert('RGB')
            save_kwargs['quality'] = quality
            save_kwargs['optimize'] = True
        elif save_format == 'PNG':
            save_kwargs['optimize'] = True
        elif save_format == 'WEBP':
            save_kwargs['quality'] = quality

        img.save(out_path, format=save_format, **save_kwargs)
        os.utime(out_path, None)
    except Exception as e:
        return {'success': False, 'error': f'transform failed: {e}'}

    try: size = os.path.getsize(out_path)
    except OSError: size = None
    return {
        'success': True,
        'operation': op,
        'inputPath': src,
        'outputPath': out_path,
        'filename': safe,
        'size': size,
        'originalSize': list(original_size),
        'newSize': list(img.size) if hasattr(img, 'size') else None,
        'note': 'Output written to /workspace/artifacts/ — auto-surfaced as a download chip.',
    }

def execute(params):
    """Read rows from an .xlsx workbook using openpyxl. Returns header + rows."""
    import os
    try:
        from openpyxl import load_workbook
    except ImportError:
        return {'success': False, 'error': 'openpyxl not installed in the sandbox image'}

    src = (params.get('path') or params.get('filePath') or params.get('sourcePath') or '').strip()
    if not src:
        return {'success': False, 'error': 'path is required'}
    if not os.path.isabs(src):
        src = os.path.join('/workspace', src)
    if not os.path.isfile(src):
        return {'success': False, 'error': f'no such file: {src}'}

    sheet_arg = params.get('sheet')
    max_rows = int(params.get('maxRows') or 1000)
    has_header = bool(params.get('header', True))
    formulas = bool(params.get('formulas', False))  # True = raw formula text; False = cached values

    try:
        wb = load_workbook(src, read_only=True, data_only=not formulas)
    except Exception as e:
        return {'success': False, 'error': f'failed to open workbook: {e}'}

    sheet_names = wb.sheetnames
    if sheet_arg is None:
        ws = wb[sheet_names[0]]
    elif isinstance(sheet_arg, int):
        if sheet_arg < 0 or sheet_arg >= len(sheet_names):
            return {'success': False, 'error': f'sheet index out of range (0..{len(sheet_names)-1})'}
        ws = wb[sheet_names[sheet_arg]]
    else:
        if sheet_arg not in sheet_names:
            return {'success': False, 'error': f'sheet "{sheet_arg}" not found. Sheets: {sheet_names}'}
        ws = wb[sheet_arg]

    headers = None
    rows = []
    truncated = False
    total_rows_seen = 0
    for i, row in enumerate(ws.iter_rows(values_only=True)):
        total_rows_seen += 1
        if i == 0 and has_header:
            headers = [str(c) if c is not None else f'col_{j}' for j, c in enumerate(row)]
            continue
        if len(rows) >= max_rows:
            truncated = True
            break
        if headers:
            rows.append({headers[j]: c for j, c in enumerate(row) if j < len(headers)})
        else:
            rows.append(list(row))

    wb.close()
    return {
        'success': True,
        'path': src,
        'sheet': ws.title,
        'sheetNames': sheet_names,
        'headers': headers,
        'rowCount': len(rows),
        'rows': rows,
        'truncated': truncated,
        'totalRowsScanned': total_rows_seen,
    }

def execute(params):
    """Run a SELECT (or other read) against a SQLite database file."""
    import os, sqlite3, re

    src = (params.get('path') or params.get('filePath') or params.get('database') or '').strip()
    if not src:
        return {'success': False, 'error': 'path is required'}
    if not os.path.isabs(src):
        src = os.path.join('/workspace', src)
    if not os.path.isfile(src):
        return {'success': False, 'error': f'no such file: {src}'}

    query = (params.get('query') or params.get('sql') or '').strip()
    if not query:
        return {'success': False, 'error': 'query is required'}

    bind = params.get('params') or []
    if not isinstance(bind, list):
        return {'success': False, 'error': 'params must be a list'}

    max_rows = int(params.get('maxRows') or 500)
    readonly = bool(params.get('readonly', True))

    # Default to read-only — opens in URI mode with mode=ro so any
    # write-bearing statement (INSERT/UPDATE/DELETE/DROP) errors out.
    # Caller must explicitly pass readonly=false to mutate.
    try:
        if readonly:
            uri = f"file:{src}?mode=ro"
            conn = sqlite3.connect(uri, uri=True)
        else:
            conn = sqlite3.connect(src)
        conn.row_factory = sqlite3.Row
    except Exception as e:
        return {'success': False, 'error': f'failed to open db: {e}'}

    try:
        cur = conn.cursor()
        cur.execute(query, tuple(bind))
        cols = [d[0] for d in cur.description] if cur.description else []
        rows = []
        truncated = False
        if cols:
            for row in cur:
                if len(rows) >= max_rows:
                    truncated = True
                    break
                rows.append({k: row[k] for k in cols})
        else:
            # DDL / mutating statement under readonly=false.
            conn.commit()
        rowcount = cur.rowcount
        cur.close()
    except Exception as e:
        conn.close()
        return {'success': False, 'error': f'query failed: {e}'}
    finally:
        try: conn.close()
        except Exception: pass

    return {
        'success': True,
        'path': src,
        'columns': cols,
        'rows': rows,
        'rowCount': len(rows),
        'truncated': truncated,
        'affectedRows': rowcount if rowcount is not None and rowcount >= 0 else None,
    }

def execute(params):
    """Transcribe an audio file to text using faster-whisper. CPU; small.en model preloaded."""
    import os, json
    try:
        from faster_whisper import WhisperModel
    except ImportError:
        return {'success': False, 'error': 'faster-whisper not installed in the sandbox image (rebuild sandbox-runtime)'}

    src = (params.get('path') or params.get('filePath') or params.get('audio') or '').strip()
    if not src:
        return {'success': False, 'error': 'path is required (workspace-relative or absolute under /workspace)'}
    if not os.path.isabs(src):
        src = os.path.join('/workspace', src)
    if not os.path.isfile(src):
        return {'success': False, 'error': f'no such file: {src}'}

    # Bundled small.en (CT2) is at /opt/whisper-models/small.en. Larger models
    # would need to be downloaded at runtime; sandbox has network=none so
    # only the bundled model works without explicit allowlist setup.
    model_size = (params.get('model') or 'small.en').strip()
    bundled = '/opt/whisper-models/' + model_size
    model_path = bundled if os.path.isdir(bundled) else model_size
    language = params.get('language')
    word_timestamps = bool(params.get('wordTimestamps', False))
    beam_size = int(params.get('beamSize') or 5)  # 5 = canonical Whisper beam; quality jump worth the cost

    try:
        # CPU compute — int8 keeps small.en fast (~30-60s for a 5-min song)
        model = WhisperModel(model_path, device='cpu', compute_type='int8')
    except Exception as e:
        return {'success': False, 'error': f'model load failed: {e}'}

    try:
        segments_iter, info = model.transcribe(
            src,
            beam_size=beam_size,
            language=language,
            word_timestamps=word_timestamps,
            vad_filter=True,
        )
        segments = []
        full_text = []
        for seg in segments_iter:
            full_text.append(seg.text)
            entry = {'start': round(seg.start, 2), 'end': round(seg.end, 2), 'text': seg.text.strip()}
            if word_timestamps and seg.words:
                entry['words'] = [
                    {'start': round(w.start, 2), 'end': round(w.end, 2), 'word': w.word, 'prob': round(w.probability, 3)}
                    for w in seg.words
                ]
            segments.append(entry)
    except Exception as e:
        return {'success': False, 'error': f'transcribe failed: {e}'}

    return {
        'success': True,
        'path': src,
        'language': info.language,
        'languageProbability': round(info.language_probability, 3),
        'durationSec': round(info.duration, 2),
        'model': model_size,
        'text': ''.join(full_text).strip(),
        'segments': segments,
        'segmentCount': len(segments),
    }

def execute(params):
    """Fetch content from a URL."""
    import urllib.request
    import urllib.error
    import json

    url = params.get('url')
    if not url:
        return {'success': False, 'error': 'url parameter is required'}

    method = params.get('method', 'GET').upper()
    headers = params.get('headers', {})
    timeout = params.get('timeout', 30)

    try:
        req = urllib.request.Request(url, method=method)
        for key, value in headers.items():
            req.add_header(key, value)

        with urllib.request.urlopen(req, timeout=timeout) as response:
            content = response.read().decode('utf-8')
            return {
                'success': True,
                'status': response.status,
                'headers': dict(response.headers),
                'content': content,
                'url': url
            }
    except urllib.error.HTTPError as e:
        return {
            'success': False,
            'error': f'HTTP {e.code}: {e.reason}',
            'status': e.code
        }
    except Exception as e:
        return {'success': False, 'error': str(e)}

