def execute(params):
    """Execute Python code."""
    import subprocess
    import tempfile
    import os

    code = params.get('code')
    if not code:
        return {'success': False, 'error': 'code parameter is required'}

    timeout = params.get('timeout', 30)

    try:
        with tempfile.NamedTemporaryFile(mode='w', suffix='.py', delete=False) as f:
            f.write(code)
            temp_file = f.name

        result = subprocess.run(
            ['python3', temp_file],
            capture_output=True,
            text=True,
            timeout=timeout
        )

        os.remove(temp_file)

        return {
            'success': True,
            'stdout': result.stdout,
            'stderr': result.stderr,
            'returncode': result.returncode
        }
    except subprocess.TimeoutExpired:
        os.remove(temp_file) if 'temp_file' in locals() else None
        return {'success': False, 'error': f'Code execution timed out after {timeout} seconds'}
    except Exception as e:
        os.remove(temp_file) if 'temp_file' in locals() else None
        return {'success': False, 'error': str(e)}

def execute(params):
    """Execute Node.js code."""
    import subprocess
    import tempfile
    import os

    code = params.get('code')
    if not code:
        return {'success': False, 'error': 'code parameter is required'}

    timeout = int(params.get('timeout') or 30)
    cwd = params.get('cwd') or ('/workspace' if os.path.isdir('/workspace') else None)

    # Pre-loaded via `node -r` so https.get / fetch / axios all honor
    # HTTPS_PROXY automatically. The sandbox network can't resolve public
    # DNS directly — only the egress proxy is reachable. Without this
    # bootstrap, `https.get('https://example.com/...')` fails with
    # EAI_AGAIN even though urllib (Python) and curl honor the proxy
    # automatically; user-facing prompt promised these "just work".
    bootstrap = "(()=>{const u=process.env.HTTPS_PROXY||process.env.https_proxy||process.env.HTTP_PROXY||process.env.http_proxy;if(!u)return;let p;try{p=new URL(u)}catch(_){return}const a=(p.username||p.password)?Buffer.from(decodeURIComponent(p.username)+':'+decodeURIComponent(p.password)).toString('base64'):null;try{const{ProxyAgent,setGlobalDispatcher}=require('undici');setGlobalDispatcher(new ProxyAgent(u))}catch(_){}try{const h=require('https'),n=require('net'),t=require('tls');const ph=p.hostname,pp=parseInt(p.port,10)||80;h.Agent.prototype.createConnection=function(o,cb){const th=o.host||o.hostname,tp=o.port||443;const s=n.connect(pp,ph);let b='';const od=(d)=>{b+=d.toString('binary');const e=b.indexOf('\\r\\n\\r\\n');if(e<0)return;s.removeListener('data',od);if(!/^HTTP\\/1\\.[01] 200/.test(b.split('\\r\\n')[0]))return cb(new Error('proxy CONNECT failed: '+b.split('\\r\\n')[0]));const ts=t.connect({socket:s,servername:th,...o},()=>cb(null,ts));ts.on('error',cb)};s.on('data',od);s.on('error',cb);s.on('connect',()=>{const L=['CONNECT '+th+':'+tp+' HTTP/1.1','Host: '+th+':'+tp];if(a)L.push('Proxy-Authorization: Basic '+a);s.write(L.join('\\r\\n')+'\\r\\n\\r\\n')})}}catch(_){}})();"

    temp_file = None
    boot_file = None
    try:
        with tempfile.NamedTemporaryFile(mode='w', suffix='.js', delete=False) as f:
            f.write(code)
            temp_file = f.name
        with tempfile.NamedTemporaryFile(mode='w', suffix='.js', delete=False, prefix='nodeproxy_') as f:
            f.write(bootstrap)
            boot_file = f.name

        result = subprocess.run(
            ['node', '-r', boot_file, temp_file],
            cwd=cwd,
            capture_output=True,
            text=True,
            timeout=timeout
        )

        return {
            'success': result.returncode == 0,
            'stdout': result.stdout,
            'stderr': result.stderr,
            'returncode': result.returncode
        }
    except subprocess.TimeoutExpired:
        return {'success': False, 'error': f'Code execution timed out after {timeout} seconds'}
    except FileNotFoundError:
        return {'success': False, 'error': 'node not found in this environment (sandbox image may be out of date - rebuild sandbox-runtime)'}
    except Exception as e:
        return {'success': False, 'error': str(e)}
    finally:
        for fp in (temp_file, boot_file):
            if fp and os.path.exists(fp):
                try:
                    os.remove(fp)
                except OSError:
                    pass

def execute(params):
    """Run an npm command in the workspace."""
    import subprocess
    import shlex
    import os

    command = (params.get('command') or '').strip()
    if not command:
        return {'success': False, 'error': 'command parameter is required (e.g. "install lodash", "run build", "list")'}

    # Reject shell metacharacters — args are passed directly to subprocess,
    # so chaining (&&, |, ;, backticks, $()) is meaningless and almost
    # always indicates the model meant to run two separate npm calls.
    forbidden = ['&', '|', ';', '`', '$(', '>', '<']
    for ch in forbidden:
        if ch in command:
            return {'success': False, 'error': f'shell metacharacter {ch!r} not allowed; pass npm args only'}

    if command.lstrip().startswith('npm '):
        command = command.split(None, 1)[1] if ' ' in command else ''

    timeout = int(params.get('timeout') or 180)

    cwd = params.get('cwd')
    if not cwd:
        cwd = '/workspace' if os.path.isdir('/workspace') else os.getcwd()
    if not os.path.isdir(cwd):
        return {'success': False, 'error': f'cwd does not exist: {cwd}'}

    try:
        args = shlex.split(command)
    except ValueError as e:
        return {'success': False, 'error': f'failed to parse command: {e}'}
    if not args:
        return {'success': False, 'error': 'command is empty after parsing'}

    cmd = ['npm', '--no-fund', '--no-audit', '--prefer-offline=false'] + args

    # The sandbox image runs with --read-only and no real $HOME for the
    # `sandbox` user. npm writes config + cache + logs under $HOME/.npm by
    # default and crashes with ENOENT on /home/sandbox. Redirect every
    # writable npm location into /tmp (mounted as tmpfs in the sandbox).
    npm_env = os.environ.copy()
    npm_env['HOME'] = '/tmp'
    npm_env['npm_config_cache'] = '/tmp/.npm-cache'
    npm_env['npm_config_prefix'] = '/tmp/.npm-global'
    npm_env['npm_config_userconfig'] = '/tmp/.npmrc'
    npm_env['npm_config_update_notifier'] = 'false'
    # Postinstall scripts are intentionally ALLOWED inside the sandbox so
    # packages that need build steps (native bindings, prebuilt-fetch) work.
    # The webapp/chat builds set ignore-scripts=true in their own .npmrc to
    # protect the host from supply-chain payloads at our build time; the
    # sandbox is gVisor-isolated, runs as non-root with --read-only rootfs,
    # and only sees the per-conversation /workspace, so script execution
    # there has a much smaller blast radius than during the host build.
    npm_env['npm_config_ignore_scripts'] = 'false'

    try:
        result = subprocess.run(
            cmd,
            cwd=cwd,
            capture_output=True,
            text=True,
            timeout=timeout,
            env=npm_env,
        )
        # npm output can be massive (full dep tree, deprecation chatter).
        # Return generous tails so the model sees the actionable bit.
        stdout = result.stdout
        stderr = result.stderr
        if len(stdout) > 12000:
            stdout = stdout[-12000:]
        if len(stderr) > 4000:
            stderr = stderr[-4000:]
        return {
            'success': result.returncode == 0,
            'cwd': cwd,
            'argv': cmd,
            'stdout': stdout,
            'stderr': stderr,
            'returncode': result.returncode,
        }
    except subprocess.TimeoutExpired:
        return {'success': False, 'error': f'npm timed out after {timeout} seconds'}
    except FileNotFoundError:
        return {'success': False, 'error': 'npm not found in this environment (sandbox image may be out of date — rebuild sandbox-runtime)'}
    except Exception as e:
        return {'success': False, 'error': str(e)}

