def execute(params):
    """Decode Base64 — accepts a single string or scans text for all base64 substrings."""
    import base64
    import re

    # Accept many aliases so the model isn't punished for guessing a different
    # parameter name from the canonical 'text'. Order matters only when more
    # than one is set: take the first non-empty.
    text = (params.get('text') or params.get('encodedData') or params.get('data')
            or params.get('input') or params.get('string') or params.get('value')
            or params.get('content') or params.get('payload') or params.get('b64')
            or params.get('encoded'))
    # Last-resort: if no named alias gave us a usable string, scan ALL
    # string-typed values in params and take the longest one. Catches
    # cases where the model picks a parameter name outside our enumerated
    # alias list (e.g. b64_data, inputString, encodedString) — base64
    # blobs are typically the longest field in a tool call, so picking
    # by length is a reliable heuristic.
    if not text or not isinstance(text, str):
        string_vals = [v for v in params.values() if isinstance(v, str) and v.strip()]
        if string_vals:
            text = max(string_vals, key=len)
    if not text or not isinstance(text, str):
        return {'success': False, 'error': "'text' parameter is required (string). Aliases also accepted: encodedData, data, input, string, value, content, payload, b64, encoded. Any string-typed parameter is also tried as a last resort."}

    def try_decode(s):
        s = s.strip()
        if not s:
            return None
        try:
            missing = (-len(s)) % 4
            padded = s + ('=' * missing)
            decoded_bytes = base64.b64decode(padded, validate=True)
            if not decoded_bytes:
                return None
            try:
                result = decoded_bytes.decode('utf-8')
            except UnicodeDecodeError:
                return f'(binary, {len(decoded_bytes)} bytes)'
            if result:
                printable = sum(1 for c in result if 32 <= ord(c) < 127 or c in '\n\r\t')
                if printable / len(result) < 0.7:
                    return None
            return result
        except Exception:
            return None

    stripped = text.strip()
    if re.fullmatch(r'[A-Za-z0-9+/]+={0,2}', stripped) and len(stripped) >= 4:
        decoded = try_decode(stripped)
        if decoded is not None:
            return {'success': True, 'decoded': decoded, 'mode': 'single'}
        return {'success': False, 'error': 'Input looks like base64 but did not decode to valid text'}

    pattern = re.compile(r'[A-Za-z0-9+/]{16,}={0,2}')
    candidates = pattern.findall(text)
    results = []
    seen = set()
    for c in candidates:
        if c in seen:
            continue
        seen.add(c)
        decoded = try_decode(c)
        if decoded is not None:
            results.append({'encoded': c, 'decoded': decoded})

    if not results:
        return {'success': False, 'error': 'No valid base64 strings found in text', 'mode': 'scan', 'scanned_chars': len(text)}

    return {
        'success': True,
        'mode': 'scan',
        'count': len(results),
        'results': results,
        'note': f'Scanned {len(text)} chars, decoded {len(results)} base64 string(s)'
    }

def execute(params):
    """Generate hash of data."""
    import hashlib

    data = params.get('data')
    if not data:
        return {'success': False, 'error': 'data parameter is required'}

    algorithm = params.get('algorithm', 'sha256').lower()

    try:
        if algorithm == 'md5':
            h = hashlib.md5()
        elif algorithm == 'sha1':
            h = hashlib.sha1()
        elif algorithm == 'sha256':
            h = hashlib.sha256()
        elif algorithm == 'sha512':
            h = hashlib.sha512()
        else:
            return {'success': False, 'error': f'Unsupported algorithm: {algorithm}'}

        h.update(data.encode('utf-8'))

        return {
            'success': True,
            'hash': h.hexdigest(),
            'algorithm': algorithm
        }
    except Exception as e:
        return {'success': False, 'error': str(e)}

