def execute(params):
    """Extract a ZIP archive."""
    import zipfile, os

    zip_path = params.get('zipPath')
    extract_path = params.get('extractPath')

    if not zip_path:
        return {'success': False, 'error': 'zipPath parameter is required'}

    if not extract_path:
        extract_path = os.path.dirname(zip_path) or '.'

    # Pre-sniff: turn cryptic BadZipFile errors into a clear "use the
    # right extractor" hint when the model misroutes a tarball/7z/rar.
    try:
        with open(zip_path, 'rb') as _bf:
            head = _bf.read(8)
    except FileNotFoundError:
        return {'success': False, 'error': f'File not found: {zip_path}. Sandbox sees only /workspace; pass /workspace/<file>.'}
    except Exception as e:
        return {'success': False, 'error': str(e)}

    if head[:4] not in (b'PK\x03\x04', b'PK\x05\x06', b'PK\x07\x08'):
        hint = ''
        if head[:2] == b'\x1f\x8b':
            hint = ' Looks like a gzip/tarball - use tar_extract (handles .tar.gz/.tgz/.tar.bz2/.tar.xz) or extract_archive.'
        elif head[:6] == b'7z\xbc\xaf\x27\x1c':
            hint = ' Looks like a 7-Zip archive - use extract_archive.'
        elif head[:4] == b'Rar!':
            hint = ' Looks like a RAR archive - use extract_archive.'
        elif head[:6] == b'\xfd7zXZ\x00':
            hint = ' Looks like xz - use tar_extract for .tar.xz or extract_archive.'
        elif head[:3] == b'BZh':
            hint = ' Looks like bzip2 - use tar_extract for .tar.bz2 or extract_archive.'
        elif head[257:262] == b'ustar':
            hint = ' Looks like a plain tar - use tar_extract or extract_archive.'
        return {'success': False, 'error': f'{zip_path} is not a ZIP file (wrong magic bytes).' + hint}

    try:
        with zipfile.ZipFile(zip_path, 'r') as zip_ref:
            zip_ref.extractall(extract_path)
            file_list = zip_ref.namelist()

        return {
            'success': True,
            'message': f'Extracted {len(file_list)} files',
            'files': file_list,
            'extractPath': extract_path
        }
    except zipfile.BadZipFile:
        return {'success': False, 'error': 'Invalid or corrupted ZIP file. If this is actually a tar/tgz/7z/rar, use tar_extract or extract_archive.'}
    except Exception as e:
        return {'success': False, 'error': str(e)}

def execute(params):
    """Create a ZIP archive."""
    import zipfile
    import os

    zip_path = params.get('zipPath')
    source_paths = params.get('sourcePaths', [])

    if not zip_path:
        return {'success': False, 'error': 'zipPath parameter is required'}

    if not source_paths:
        return {'success': False, 'error': 'sourcePaths parameter is required'}

    try:
        with zipfile.ZipFile(zip_path, 'w', zipfile.ZIP_DEFLATED) as zip_ref:
            file_count = 0
            for source_path in source_paths:
                if os.path.isfile(source_path):
                    zip_ref.write(source_path, os.path.basename(source_path))
                    file_count += 1
                elif os.path.isdir(source_path):
                    for root, dirs, files in os.walk(source_path):
                        for file in files:
                            file_path = os.path.join(root, file)
                            arcname = os.path.relpath(file_path, os.path.dirname(source_path))
                            zip_ref.write(file_path, arcname)
                            file_count += 1

        return {
            'success': True,
            'message': f'Created ZIP with {file_count} files',
            'zipPath': zip_path,
            'fileCount': file_count
        }
    except Exception as e:
        return {'success': False, 'error': str(e)}

def execute(params):
    """Read and parse a saved email file (.eml or .msg format).

    Enhanced features:
    - Extract content from PDF, DOCX, XLSX, TXT attachments
    - Parse nested/attached emails (.eml within .msg, including embedded Message objects)
    - Extract URLs from QR codes in image attachments
    - Robust link extraction from HTML email bodies
    - Proper HTML entity decoding using html.unescape()
    - Content-based email detection for attachments without proper extensions
    """
    import email
    from email.header import decode_header
    import os
    import re
    import io
    import html
    import tempfile

    email_path = params.get('emailPath')
    extract_attachments = params.get('extractAttachments', True)

    if not email_path:
        return {'success': False, 'error': 'emailPath parameter is required'}

    def html_to_text(html_content):
        """Convert HTML to readable text with proper entity decoding."""
        if not html_content:
            return ""
        text = html_content
        if isinstance(text, bytes):
            text = text.decode('utf-8', errors='replace')
        # Remove style and script blocks
        text = re.sub(r'<style[^>]*>.*?</style>', '', text, flags=re.IGNORECASE | re.DOTALL)
        text = re.sub(r'<script[^>]*>.*?</script>', '', text, flags=re.IGNORECASE | re.DOTALL)
        # Convert block elements
        text = re.sub(r'<br\s*/?>', '\n', text, flags=re.IGNORECASE)
        text = re.sub(r'</p>', '\n\n', text, flags=re.IGNORECASE)
        text = re.sub(r'</div>', '\n', text, flags=re.IGNORECASE)
        text = re.sub(r'<li[^>]*>', '\n- ', text, flags=re.IGNORECASE)
        # Remove remaining tags
        text = re.sub(r'<[^>]+>', '', text)
        # Decode ALL HTML entities using html.unescape()
        text = html.unescape(text)
        # Clean whitespace
        text = re.sub(r'[ \t]+', ' ', text)
        text = re.sub(r'\n\s*\n\s*\n+', '\n\n', text)
        return text.strip()

    def extract_links(html_content):
        """Extract links from HTML content."""
        links = []
        pattern = r'<a\s+[^>]*href=["\'](https?://[^"\' ]+)["\'][^>]*>([^<]*)</a>'
        for match in re.finditer(pattern, html_content, re.IGNORECASE):
            url = match.group(1)
            text = match.group(2).strip()
            links.append({'url': url, 'text': text or url})
        # Also find plain URLs
        url_pattern = r'https?://[^\s<>"\')\]]+'
        for url in re.findall(url_pattern, html_content):
            if not any(l['url'] == url for l in links):
                links.append({'url': url, 'text': url})
        return links

    def is_email_content(data):
        """Detect if binary data looks like an email (RFC 822 format)."""
        try:
            text_start = data[:2000].decode('utf-8', errors='replace')
            email_patterns = [r'^From:', r'^Received:', r'^Return-Path:', r'^MIME-Version:',
                              r'^Date:.*\d{4}', r'^Message-ID:', r'^Subject:', r'^Content-Type:.*multipart']
            for pattern in email_patterns:
                if re.search(pattern, text_start, re.MULTILINE | re.IGNORECASE):
                    return True
            return False
        except:
            return False

    def is_msg_content(data):
        """Detect if binary data is an Outlook .msg file (OLE2 format)."""
        return len(data) >= 8 and data[:8] == b'\xd0\xcf\x11\xe0\xa1\xb1\x1a\xe1'

    def extract_qr_urls(image_data):
        """Extract URLs from QR codes in images."""
        urls = []
        try:
            from PIL import Image
            try:
                import pyzbar.pyzbar as pyzbar
                img = Image.open(io.BytesIO(image_data))
                if img.mode not in ('RGB', 'L'):
                    img = img.convert('RGB')
                decoded = pyzbar.decode(img)
                for obj in decoded:
                    if obj.type == 'QRCODE':
                        data = obj.data.decode('utf-8', errors='replace')
                        if data.startswith('http'):
                            urls.append(data)
                        elif re.match(r'^[a-zA-Z0-9.-]+\.[a-zA-Z]{2,}', data):
                            urls.append(f'https://{data}')
                        else:
                            urls.append(f'[QR: {data}]')
            except ImportError:
                pass
        except Exception:
            pass
        return urls

    def extract_pdf_text(pdf_data):
        """Extract text from PDF."""
        try:
            from PyPDF2 import PdfReader
            reader = PdfReader(io.BytesIO(pdf_data))
            text = ""
            for page in reader.pages:
                t = page.extract_text()
                if t:
                    text += t + "\n"
            return text.strip()
        except:
            return ""

    def extract_docx_text(docx_data):
        """Extract text from DOCX."""
        try:
            from docx import Document
            doc = Document(io.BytesIO(docx_data))
            return "\n".join(p.text for p in doc.paragraphs if p.text.strip())
        except:
            return ""

    def extract_xlsx_text(xlsx_data):
        """Extract text from XLSX."""
        try:
            import openpyxl
            wb = openpyxl.load_workbook(io.BytesIO(xlsx_data), data_only=True)
            text = ""
            for sheet in wb.sheetnames:
                ws = wb[sheet]
                text += f"[Sheet: {sheet}]\n"
                for row in ws.iter_rows(values_only=True):
                    row_text = "\t".join(str(c) if c else "" for c in row)
                    if row_text.strip():
                        text += row_text + "\n"
            return text.strip()
        except:
            return ""

    def parse_nested_email(data, ext):
        """Parse nested email attachment."""
        result = {'subject': '', 'from': '', 'to': '', 'body': '', 'attachments': []}
        try:
            if ext.lower() == '.msg':
                import extract_msg
                with tempfile.NamedTemporaryFile(suffix='.msg', delete=False) as tmp:
                    tmp.write(data)
                    tmp_path = tmp.name
                msg = extract_msg.Message(tmp_path)
                result['subject'] = msg.subject or ''
                result['from'] = msg.sender or ''
                result['to'] = msg.to or ''
                result['body'] = msg.body or ''
                if not result['body'] and msg.htmlBody:
                    result['body'] = html_to_text(msg.htmlBody)
                if hasattr(msg, 'attachments') and msg.attachments:
                    for att in msg.attachments:
                        att_name = getattr(att, 'longFilename', None) or getattr(att, 'shortFilename', None) or 'unnamed'
                        result['attachments'].append(att_name)
                msg.close()
                os.unlink(tmp_path)
            else:
                msg = email.message_from_bytes(data)
                subj = msg.get('Subject', '')
                if subj:
                    parts = decode_header(subj)
                    subj = ''.join(c.decode(e or 'utf-8') if isinstance(c, bytes) else c for c, e in parts)
                result['subject'] = subj
                result['from'] = msg.get('From', '')
                result['to'] = msg.get('To', '')
                if msg.is_multipart():
                    for part in msg.walk():
                        ct = part.get_content_type()
                        disp = part.get_content_disposition()
                        if ct == 'text/plain' and not result['body'] and disp != 'attachment':
                            try:
                                result['body'] = part.get_payload(decode=True).decode('utf-8', errors='replace')
                            except:
                                pass
                        elif ct == 'text/html' and not result['body'] and disp != 'attachment':
                            try:
                                result['body'] = html_to_text(part.get_payload(decode=True).decode('utf-8', errors='replace'))
                            except:
                                pass
                        elif disp == 'attachment':
                            fname = part.get_filename()
                            if fname:
                                result['attachments'].append(fname)
                else:
                    try:
                        result['body'] = msg.get_payload(decode=True).decode('utf-8', errors='replace')
                    except:
                        pass
        except:
            pass
        return result

    def process_attachment(data, filename, mimetype):
        """Extract content from attachment with content-based email detection."""
        result = {'type': 'unknown', 'text': '', 'qr_urls': [], 'nested_email': None}
        if not data:
            return result
        ext = os.path.splitext(filename.lower())[1] if filename else ''

        # First check for embedded emails by content signature (more reliable)
        if is_msg_content(data):
            result['type'] = 'email'
            result['nested_email'] = parse_nested_email(data, '.msg')
            return result
        if is_email_content(data):
            result['type'] = 'email'
            result['nested_email'] = parse_nested_email(data, '.eml')
            return result

        # Images - check for QR codes
        if ext in ['.png', '.jpg', '.jpeg', '.gif', '.bmp', '.webp']:
            result['type'] = 'image'
            result['qr_urls'] = extract_qr_urls(data)
        # PDF
        elif ext == '.pdf':
            result['type'] = 'pdf'
            result['text'] = extract_pdf_text(data)
        # Word
        elif ext == '.docx':
            result['type'] = 'docx'
            result['text'] = extract_docx_text(data)
        # Excel
        elif ext == '.xlsx':
            result['type'] = 'xlsx'
            result['text'] = extract_xlsx_text(data)
        # Text files
        elif ext in ['.txt', '.csv', '.log', '.json', '.xml', '.md']:
            result['type'] = 'text'
            try:
                result['text'] = data.decode('utf-8', errors='replace')
            except:
                pass
        # Nested emails (fallback by extension/mimetype)
        elif ext in ['.eml', '.msg'] or mimetype in ['message/rfc822', 'application/vnd.ms-outlook']:
            result['type'] = 'email'
            result['nested_email'] = parse_nested_email(data, ext if ext else '.eml')
        return result

    try:
        file_ext = os.path.splitext(email_path)[1].lower()

        if file_ext == '.msg':
            try:
                import extract_msg
            except ImportError:
                return {'success': False, 'error': 'extract_msg module not installed'}

            msg = extract_msg.Message(email_path)
            subject = msg.subject or ''
            from_addr = msg.sender or ''
            to_addr = msg.to or ''
            cc = msg.cc or ''
            date = str(msg.date) if msg.date else ''
            body = msg.body or ''
            html_body = msg.htmlBody or ''

            # Extract links from body
            links = []
            if html_body:
                if isinstance(html_body, bytes):
                    html_body = html_body.decode('utf-8', errors='replace')
                links = extract_links(html_body)
                if not body:
                    body = html_to_text(html_body)

            # Process attachments
            attachments = []
            attachment_contents = []
            nested_emails = []
            qr_urls = []

            for att in msg.attachments:
                filename = getattr(att, 'longFilename', None) or getattr(att, 'shortFilename', None) or 'unknown'
                att_data = getattr(att, 'data', None)
                mimetype = getattr(att, 'mimetype', '') or ''

                # Check if attachment is an embedded Message object (extract_msg represents these differently)
                att_class = type(att).__name__
                is_embedded_msg = ('Message' in att_class and att_class != 'Attachment') or hasattr(att, 'subject') or hasattr(att, 'htmlBody')

                size = len(att_data) if att_data else 0
                attachments.append({'filename': filename, 'content_type': mimetype or 'application/octet-stream', 'size': size})

                # Handle embedded Message objects directly
                if extract_attachments and is_embedded_msg:
                    try:
                        nested_content = {
                            'subject': getattr(att, 'subject', '') or '',
                            'from': getattr(att, 'sender', '') or '',
                            'to': getattr(att, 'to', '') or '',
                            'body': '',
                            'attachments': []
                        }
                        if hasattr(att, 'body') and att.body:
                            nested_content['body'] = att.body
                        elif hasattr(att, 'htmlBody') and att.htmlBody:
                            nested_content['body'] = html_to_text(att.htmlBody)
                        if hasattr(att, 'attachments') and att.attachments:
                            for nested_att in att.attachments:
                                nested_name = getattr(nested_att, 'longFilename', None) or getattr(nested_att, 'shortFilename', None) or 'unnamed'
                                nested_content['attachments'].append(nested_name)
                        nested_emails.append({'filename': filename, **nested_content})
                    except:
                        pass
                # Extract content from regular attachments
                elif extract_attachments and att_data:
                    extracted = process_attachment(att_data, filename, mimetype)
                    if extracted['text']:
                        attachment_contents.append({'filename': filename, 'type': extracted['type'], 'content': extracted['text'][:5000]})
                    if extracted['qr_urls']:
                        qr_urls.extend(extracted['qr_urls'])
                    if extracted['nested_email']:
                        nested_emails.append({'filename': filename, **extracted['nested_email']})

            msg.close()

            return {
                'success': True, 'format': 'msg', 'subject': subject, 'from': from_addr, 'to': to_addr,
                'cc': cc, 'date': date, 'body': body, 'html_body': html_body, 'links': links,
                'attachments': attachments, 'attachment_contents': attachment_contents,
                'nested_emails': nested_emails, 'qr_urls': qr_urls, 'emailPath': email_path
            }
        else:
            # Handle .eml format
            with open(email_path, 'rb') as f:
                msg = email.message_from_bytes(f.read())

            # Decode subject
            subject = msg.get('Subject', '')
            if subject:
                decoded_parts = decode_header(subject)
                subject = ''
                for content, encoding in decoded_parts:
                    if isinstance(content, bytes):
                        subject += content.decode(encoding or 'utf-8', errors='replace')
                    else:
                        subject += content

            from_addr = msg.get('From', '')
            to_addr = msg.get('To', '')
            date = msg.get('Date', '')
            cc = msg.get('Cc', '')

            body = ''
            html_body = ''
            links = []
            attachments = []
            attachment_contents = []
            nested_emails = []
            qr_urls = []

            if msg.is_multipart():
                for part in msg.walk():
                    content_type = part.get_content_type()
                    disposition = part.get_content_disposition()

                    # Also detect inline embedded emails by content-type
                    if content_type == 'message/rfc822':
                        payload = part.get_payload(decode=True)
                        if not payload and hasattr(part, 'get_payload'):
                            sub_msg = part.get_payload()
                            if isinstance(sub_msg, list) and len(sub_msg) > 0:
                                sub_msg = sub_msg[0]
                            if hasattr(sub_msg, 'as_bytes'):
                                payload = sub_msg.as_bytes()
                        if payload:
                            nested = parse_nested_email(payload, '.eml')
                            nested_emails.append({'filename': 'embedded.eml', **nested})
                        continue

                    if content_type == 'text/plain' and not body and disposition != 'attachment':
                        try:
                            body = part.get_payload(decode=True).decode('utf-8', errors='replace')
                        except:
                            body = str(part.get_payload())
                    elif content_type == 'text/html' and not html_body and disposition != 'attachment':
                        try:
                            html_body = part.get_payload(decode=True).decode('utf-8', errors='replace')
                            links = extract_links(html_body)
                        except:
                            html_body = str(part.get_payload())
                    elif disposition == 'attachment' or (disposition is None and part.get_filename()):
                        filename = part.get_filename()
                        if filename:
                            decoded_parts = decode_header(filename)
                            filename = ''
                            for content, encoding in decoded_parts:
                                if isinstance(content, bytes):
                                    filename += content.decode(encoding or 'utf-8', errors='replace')
                                else:
                                    filename += content

                            payload = part.get_payload(decode=True)
                            attachments.append({'filename': filename, 'content_type': content_type, 'size': len(payload) if payload else 0})

                            # Extract content
                            if extract_attachments and payload:
                                extracted = process_attachment(payload, filename, content_type)
                                if extracted['text']:
                                    attachment_contents.append({'filename': filename, 'type': extracted['type'], 'content': extracted['text'][:5000]})
                                if extracted['qr_urls']:
                                    qr_urls.extend(extracted['qr_urls'])
                                if extracted['nested_email']:
                                    nested_emails.append({'filename': filename, **extracted['nested_email']})
            else:
                try:
                    body = msg.get_payload(decode=True).decode('utf-8', errors='replace')
                except:
                    body = str(msg.get_payload())

            # If no plain body, convert HTML
            if not body and html_body:
                body = html_to_text(html_body)

            return {
                'success': True, 'format': 'eml', 'subject': subject, 'from': from_addr, 'to': to_addr,
                'cc': cc, 'date': date, 'body': body, 'html_body': html_body, 'links': links,
                'attachments': attachments, 'attachment_contents': attachment_contents,
                'nested_emails': nested_emails, 'qr_urls': qr_urls, 'emailPath': email_path
            }
    except FileNotFoundError:
        return {'success': False, 'error': f'Email file not found: {email_path}. If this file was uploaded via the chat UI in this turn or earlier in the conversation, it is at /workspace/uploads/<name>. Pass that path, or call list_directory on /workspace/uploads to see what is there. The same content is also embedded inline in the === FILE N === blocks of the originating user message for immediate access without a tool call.'}
    except Exception as e:
        return {'success': False, 'error': str(e)}

