def execute(params):
    """Download a web page's raw HTML into the workspace so other tools can parse the full, untruncated page."""
    import os, re
    from urllib.parse import urlparse

    url = (params.get('url') or '').strip()
    if not url:
        return {'success': False, 'error': 'url parameter is required'}
    if not re.match(r'^https?://', url, re.I):
        url = 'https://' + url

    filename = (params.get('filename') or '').strip()
    if not filename:
        p = urlparse(url)
        base = (p.netloc + p.path).strip('/').replace('/', '_') or (p.netloc or 'page')
        base = re.sub(r'[^A-Za-z0-9._-]+', '_', base)[:80] or 'page'
        filename = base if base.lower().endswith(('.html', '.htm')) else base + '.html'
    filename = os.path.basename(filename)

    headers = {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36',
        'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
        'Accept-Language': 'en-US,en;q=0.9',
    }
    try:
        timeout = int(params.get('timeout') or 30)
    except Exception:
        timeout = 30

    html = None
    status = None
    try:
        import requests
        r = requests.get(url, headers=headers, timeout=timeout, allow_redirects=True)
        html = r.text
        status = r.status_code
    except Exception as e:
        try:
            import urllib.request
            req = urllib.request.Request(url, headers=headers)
            with urllib.request.urlopen(req, timeout=timeout) as resp:
                html = resp.read().decode('utf-8', errors='replace')
                status = getattr(resp, 'status', 200)
        except Exception as e2:
            return {'success': False, 'error': 'Fetch failed: ' + str(e2)}

    if html is None:
        return {'success': False, 'error': 'Fetch failed'}

    out_dir = '/workspace' if os.path.isdir('/workspace') else os.getcwd()
    out_path = os.path.join(out_dir, filename)
    try:
        with open(out_path, 'w', encoding='utf-8') as f:
            f.write(html)
        size = os.path.getsize(out_path)
    except Exception as e:
        return {'success': False, 'error': 'Failed to save HTML: ' + str(e)}

    m = re.search(r'<title[^>]*>(.*?)</title>', html, re.I | re.S)
    title = re.sub(r'\s+', ' ', m.group(1)).strip()[:200] if m else ''
    blocked = bool(re.search(r'(just a moment|checking your browser|cf-browser-verification|access denied|captcha)', html[:4000], re.I))
    return {
        'success': True,
        'message': 'Saved ' + str(size) + ' bytes of HTML to ' + filename,
        'file': filename,
        'workspacePath': out_path,
        'size': size,
        'httpStatus': status,
        'title': title,
        'hint': ('Page looks bot-protected - retry with scrapling_fetch for the content. ' if blocked else '') + 'Now parse it with read_file / grep_code / parse_html on this file (avoids re-fetching with truncation).'
    }

