def execute(params):
    """Generate a .docx document in /artifacts using python-docx."""
    import os, re
    try:
        from docx import Document
    except ImportError:
        return {'success': False, 'error': 'python-docx not installed in the sandbox image (rebuild sandbox-runtime)'}

    raw_name = (params.get('filename') or params.get('outputPath') or 'document.docx').strip()
    title = (params.get('title') or '').strip()
    content = params.get('content') or ''
    # contentFile lets the model bypass the per-turn arg-token cap for
    # very long documents: write markdown to /workspace/<name>.md via
    # create_file + append_to_file, then pass the path here. Resolves
    # relative paths against /workspace/. When both content and
    # contentFile are given, contentFile wins (avoids surprising the
    # user with a half-merged document).
    content_file = (params.get('contentFile') or params.get('content_file') or '').strip()
    if content_file:
        cf_path = content_file if content_file.startswith('/') else os.path.join('/workspace', content_file)
        try:
            with open(cf_path, 'r', encoding='utf-8') as _cf:
                content = _cf.read()
        except FileNotFoundError:
            return {'success': False, 'error': f'contentFile not found: {cf_path}. Write the markdown there first via create_file / append_to_file, then retry.'}
        except UnicodeDecodeError:
            with open(cf_path, 'rb') as _cf:
                content = _cf.read().decode('utf-8', errors='replace')
    if not content and not title:
        return {'success': False, 'error': 'content (inline), contentFile (workspace path), or title is required'}

    base = os.path.basename(raw_name) or 'document.docx'
    if not base.lower().endswith('.docx'):
        base = base + '.docx'
    base = re.sub(r'[^A-Za-z0-9._\-]', '_', base)[:120] or 'document.docx'

    # Prefer /workspace/artifacts/ — persists across skill calls so
    # follow-up tools can still see the file. /artifacts/ is the per-run
    # ephemeral mount; /tmp is the last-resort fallback when neither is
    # mounted. The post-run scan promotes either into the download chip.
    if os.path.isdir('/workspace'):
        artifacts_dir = '/workspace/artifacts'
        os.makedirs(artifacts_dir, exist_ok=True)
    elif os.path.isdir('/artifacts'):
        artifacts_dir = '/artifacts'
    else:
        artifacts_dir = '/tmp'
    out_path = os.path.join(artifacts_dir, base)

    doc = Document()
    if title:
        doc.add_heading(title, level=0)

    blocks = re.split(r'\n\s*\n', content.strip())
    for blk in blocks:
        blk = blk.rstrip()
        if not blk:
            continue
        if blk.startswith('# '):
            doc.add_heading(blk[2:].strip(), level=1)
        elif blk.startswith('## '):
            doc.add_heading(blk[3:].strip(), level=2)
        else:
            doc.add_paragraph(blk)

    try:
        doc.save(out_path)
    except Exception as e:
        return {'success': False, 'error': f'docx write failed: {e}'}

    try:
        size = os.path.getsize(out_path)
    except OSError:
        size = None

    return {
        'success': True,
        'filename': base,
        'path': out_path,
        'size': size,
        'note': 'DOCX written to /workspace/artifacts/. The chat UI already shows this as a download chip — do NOT call make_downloadable, copy_file, or list_directory on it as a follow-up.',
    }

def execute(params):
    """Generate an .xlsx spreadsheet in /artifacts using openpyxl."""
    import os, re
    try:
        from openpyxl import Workbook
        from openpyxl.styles import Font
    except ImportError:
        return {'success': False, 'error': 'openpyxl not installed in the sandbox image (rebuild sandbox-runtime)'}

    raw_name = (params.get('filename') or 'data.xlsx').strip()
    sheet_name = (params.get('sheetName') or 'Sheet1').strip()[:31] or 'Sheet1'
    headers = params.get('headers') or []
    rows = params.get('rows') or []

    if not isinstance(headers, list) or not isinstance(rows, list):
        return {'success': False, 'error': 'headers and rows must be arrays'}
    if not headers and not rows:
        return {'success': False, 'error': 'headers or rows is required'}

    base = os.path.basename(raw_name) or 'data.xlsx'
    if not base.lower().endswith('.xlsx'):
        base = base + '.xlsx'
    base = re.sub(r'[^A-Za-z0-9._\-]', '_', base)[:120] or 'data.xlsx'

    # Prefer /workspace/artifacts/ — persists across skill calls so
    # follow-up tools can still see the file. /artifacts/ is the per-run
    # ephemeral mount; /tmp is the last-resort fallback when neither is
    # mounted. The post-run scan promotes either into the download chip.
    if os.path.isdir('/workspace'):
        artifacts_dir = '/workspace/artifacts'
        os.makedirs(artifacts_dir, exist_ok=True)
    elif os.path.isdir('/artifacts'):
        artifacts_dir = '/artifacts'
    else:
        artifacts_dir = '/tmp'
    out_path = os.path.join(artifacts_dir, base)

    wb = Workbook()
    ws = wb.active
    ws.title = sheet_name
    if headers:
