            continue
        ws.append(r)

    try:
        wb.save(out_path)
    except Exception as e:
        return {'success': False, 'error': f'xlsx write failed: {e}'}

    try:
        size = os.path.getsize(out_path)
    except OSError:
        size = None

    return {
        'success': True,
        'filename': base,
        'path': out_path,
        'size': size,
        'rowCount': len(rows),
        'columnCount': len(headers) if headers else (len(rows[0]) if rows and isinstance(rows[0], list) else 0),
        'note': 'XLSX written to /workspace/artifacts/. The chat UI already shows this as a download chip — do NOT call make_downloadable, copy_file, or list_directory on it as a follow-up.',
    }

def execute(params):
    """Generate a standards-compliant .eml file (RFC 5322 / 2045) in
    /workspace/artifacts/. Plain-text body + optional HTML alternative,
    multiple recipients (To/Cc/Bcc), Reply-To, custom headers, and
    workspace-path attachments. Output surfaces in the chat UI as a
    download chip via the post-run /workspace/artifacts/ promotion."""
    import os, re, mimetypes
    from email.message import EmailMessage
    from email.utils import formatdate, make_msgid, formataddr

    raw_name   = (params.get('filename') or 'message.eml').strip()
    from_addr  = (params.get('from') or params.get('sender') or '').strip()
    subject    = (params.get('subject') or '').strip()
    body       = params.get('body') or params.get('text') or ''
    html_body  = params.get('html') or params.get('htmlBody') or ''
    reply_to   = (params.get('replyTo') or params.get('reply_to') or '').strip()
    date_hdr   = (params.get('date') or '').strip()
    extra_hdrs = params.get('headers') or {}
    atts       = params.get('attachments') or []

    def _addrs(v):
        if not v:
            return []
        if isinstance(v, str):
            return [a.strip() for a in re.split(r'[,;]', v) if a.strip()]
        if isinstance(v, list):
            out = []
            for item in v:
                if isinstance(item, str):
                    s = item.strip()
                    if s:
                        out.append(s)
                elif isinstance(item, dict):
                    name = (item.get('name') or '').strip()
                    addr = (item.get('email') or item.get('address') or '').strip()
                    if addr:
                        out.append(formataddr((name, addr)) if name else addr)
            return out
        return []

    to_list  = _addrs(params.get('to'))
    cc_list  = _addrs(params.get('cc'))
    bcc_list = _addrs(params.get('bcc'))

    if not from_addr:
        return {'success': False, 'error': 'from is required (e.g. "alice@example.com" or "Alice <alice@example.com>")'}
    if not (to_list or cc_list or bcc_list):
        return {'success': False, 'error': 'at least one recipient (to/cc/bcc) is required'}
    if not subject and not body and not html_body:
        return {'success': False, 'error': 'subject, body, or html is required'}

    base = os.path.basename(raw_name) or 'message.eml'
    if not base.lower().endswith('.eml'):
        base = base + '.eml'
    # Hyphen at end of [] class is literal, no backslash needed.
    base = re.sub(r'[^A-Za-z0-9._-]', '_', base)[:120] or 'message.eml'

    if os.path.isdir('/workspace'):
        artifacts_dir = '/workspace/artifacts'
        os.makedirs(artifacts_dir, exist_ok=True)
    elif os.path.isdir('/artifacts'):
        artifacts_dir = '/artifacts'
    else:
        artifacts_dir = '/tmp'
    out_path = os.path.join(artifacts_dir, base)

    msg = EmailMessage()
    msg['From'] = from_addr
    if to_list:
        msg['To'] = ', '.join(to_list)
    if cc_list:
        msg['Cc'] = ', '.join(cc_list)
    if bcc_list:
        msg['Bcc'] = ', '.join(bcc_list)
    msg['Subject'] = subject
    if reply_to:
        msg['Reply-To'] = reply_to
    msg['Date'] = date_hdr or formatdate(localtime=True)
    try:
        domain = from_addr.split('@', 1)[1].strip(' <>')
        msg['Message-ID'] = make_msgid(domain=domain) if domain else make_msgid()
    except Exception:
        msg['Message-ID'] = make_msgid()

    RESERVED = {
        'from', 'to', 'cc', 'bcc', 'subject', 'date', 'message-id',
        'reply-to', 'content-type', 'content-transfer-encoding',
        'mime-version',
    }
    if isinstance(extra_hdrs, dict):
        for k, v in extra_hdrs.items():
            if not k or str(k).lower() in RESERVED:
                continue
            try:
                msg[str(k)] = str(v)
            except Exception:
                pass

    # Plain-text + optional HTML alternative. EmailMessage wraps in
    # multipart/alternative automatically when add_alternative follows
    # set_content.
    msg.set_content(body if body else '')
    if html_body:
        msg.add_alternative(html_body, subtype='html')

    attached = []
    skipped = []
    if isinstance(atts, list):
        for a in atts:
            try:
                if isinstance(a, str):
                    path, fname, mime = a, None, None
                elif isinstance(a, dict):
                    path = a.get('path') or a.get('filePath') or a.get('file')
                    fname = a.get('filename') or a.get('name')
                    mime = a.get('mimeType') or a.get('mime') or a.get('contentType')
                else:
                    continue
                if not path:
                    continue
                full = path if str(path).startswith('/') else os.path.join('/workspace', str(path))
                if not os.path.isfile(full):
                    skipped.append({'path': str(path), 'reason': 'not found (sandbox sees only /workspace; pass /workspace/<file> or a path relative to it)'})
                    continue
                if not mime:
                    mime = mimetypes.guess_type(full)[0] or 'application/octet-stream'
                maintype, _, subtype = mime.partition('/')
                with open(full, 'rb') as f:
                    data = f.read()
                msg.add_attachment(
                    data,
                    maintype=maintype or 'application',
                    subtype=subtype or 'octet-stream',
                    filename=fname or os.path.basename(full),
                )
                attached.append({
                    'path': full,
                    'filename': fname or os.path.basename(full),
                    'size': len(data),
                    'mimeType': mime,
                })
            except Exception as e:
                skipped.append({'path': str(a), 'reason': str(e)})

    try:
        with open(out_path, 'wb') as f:
            f.write(bytes(msg))
    except Exception as e:
        return {'success': False, 'error': 'eml write failed: ' + str(e)}

    try:
        size = os.path.getsize(out_path)
    except OSError:
        size = None

    return {
        'success': True,
        'filename': base,
        'path': out_path,
        'size': size,
        'subject': subject,
        'recipients': {'to': to_list, 'cc': cc_list, 'bcc': bcc_list},
        'attachments': attached,
        'skippedAttachments': skipped,
        'hasHtml': bool(html_body),
        'note': 'EML written to /workspace/artifacts/. The chat UI already shows this as a download chip — do NOT call make_downloadable, copy_file, or list_directory on it as a follow-up.',
    }

