def execute(params):
    """Compare two files and show differences."""
    import difflib, os

    file1 = params.get('file1')
    file2 = params.get('file2')

    if not file1 or not file2:
        return {'success': False, 'error': 'file1 and file2 parameters are required'}

    if not os.path.isfile(file1):
        return {'success': False, 'error': 'File not found: ' + str(file1) + '. (sandbox sees only /workspace; pass /workspace/<file> or a path relative to it)'}
    if not os.path.isfile(file2):
        return {'success': False, 'error': 'File not found: ' + str(file2) + '. (sandbox sees only /workspace; pass /workspace/<file> or a path relative to it)'}

    try:
        with open(file1, 'r') as f:
            content1 = f.readlines()
        with open(file2, 'r') as f:
            content2 = f.readlines()

        diff = list(difflib.unified_diff(content1, content2, fromfile=file1, tofile=file2))

        return {
            'success': True,
            'file1': file1,
            'file2': file2,
            'diff': ''.join(diff),
            'identical': len(diff) == 0
        }
    except Exception as e:
        return {'success': False, 'error': str(e)}

def execute(params):
    """Search and replace text in a file."""
    import re

    file_path = params.get('filePath')
    search = params.get('search')
    replace = params.get('replace', '')
    use_regex = params.get('regex', False)

    if not file_path or not search:
        return {'success': False, 'error': 'filePath and search parameters are required'}

    try:
        with open(file_path, 'r') as f:
