                    continue
                done_items.append({'line_no': idx, 'text': text})
    out = {'success': True, 'file': file_path, 'total': len(open_items) + len(done_items)}
    if show == 'done':
        out['done'] = done_items
    elif show == 'all':
        out['open'] = open_items
        out['done'] = done_items
    else:
        out['open'] = open_items
