            default_out = '/tmp/chart_' + h + '.png'
        out_path = params.get('output') or default_out
        try:
            with open(out_path, 'wb') as fp:
                fp.write(png_bytes)
        except Exception:
            pass
        return {
            'success': True,
            'type': chart_type,
            'png_base64': png_b64,
            'data_url': 'data:image/png;base64,' + png_b64,
            'file': out_path,
            'workspacePath': out_path,
            'bytes': len(png_bytes),
            'note': 'DO NOT echo png_base64 or data_url in your reply. UI renders the chart from this tool result automatically.',
        }
    except Exception as e:
        return {'success': False, 'error': str(e)}

