def execute(params):
    import os, re, subprocess, hashlib, shutil, time
    repo = (params.get('repo') or '').strip()
    if not repo:
        return {'success': False, 'error': 'repo required (owner/name, github URL, or git URL)'}
    ref = (params.get('ref') or '').strip()
    shallow = params.get('shallow', True) if params.get('shallow') is not None else True
    timeout_s = int(params.get('timeout_s') or 120)
    size_limit_mb = int(params.get('size_limit_mb') or 500)

    clone_url = repo
    if re.match(r'^[A-Za-z0-9._-]+/[A-Za-z0-9._-]+$', repo):
        clone_url = 'https://github.com/' + repo + '.git'
    elif 'github.com/' in repo and not repo.endswith('.git'):
        m = re.search(r'github\.com/([^/\s]+)/([^/\s#?]+)', repo)
        if m:
            clone_url = 'https://github.com/' + m.group(1) + '/' + m.group(2) + '.git'

    # Inside the sandbox, /workspace is bind-mounted from the host (per-user).
    # Outside the sandbox (legacy in-process path), fall back to /tmp.
    base_parent = '/workspace' if os.path.isdir('/workspace') else '/tmp'
    base_dir = os.path.join(base_parent, 'gh-clones')
    os.makedirs(base_dir, exist_ok=True)

    key = hashlib.sha1((clone_url + '|' + (ref or '')).encode()).hexdigest()[:12]
    target = os.path.join(base_dir, key)

    # TTL sweep: nuke sibling clones older than 24h (only inside base_dir).
    try:
        now = time.time()
        for name in os.listdir(base_dir):
            p = os.path.join(base_dir, name)
            try:
                if p != target and os.path.isdir(p) and now - os.path.getmtime(p) > 86400:
                    shutil.rmtree(p, ignore_errors=True)
            except Exception:
                pass
    except Exception:
        pass

    if os.path.isdir(os.path.join(target, '.git')):
        try:
            sha_r = subprocess.run(['git', '-C', target, 'rev-parse', 'HEAD'],
                                   capture_output=True, text=True, timeout=10)
            head_sha = sha_r.stdout.strip() if sha_r.returncode == 0 else None
        except Exception:
            head_sha = None
        return {
            'success': True,
            'cached': True,
            'repo': repo,
            'clone_url': clone_url,
            'path': target,
            'ref': ref or 'default',
            'head_sha': head_sha,
            'note': 'Already cloned. Use list_directory(path=...) / read_file(filePath=...) / git_list_tree(repoPath=...) on ' + target,
        }

    cmd = ['git', 'clone']
    if shallow:
        cmd += ['--depth', '1']
        if ref and re.match(r'^[0-9a-f]{7,40}$', ref):
            cmd += [clone_url, target]
        elif ref:
            cmd += ['--branch', ref, clone_url, target]
        else:
            cmd += [clone_url, target]
    else:
        cmd += [clone_url, target]

    try:
        r = subprocess.run(cmd, capture_output=True, text=True, timeout=timeout_s)
    except subprocess.TimeoutExpired:
        shutil.rmtree(target, ignore_errors=True)
        return {'success': False, 'error': 'clone timed out after ' + str(timeout_s) + 's'}
    except Exception as e:
        shutil.rmtree(target, ignore_errors=True)
        return {'success': False, 'error': 'clone failed: ' + str(e)}
    if r.returncode != 0:
        shutil.rmtree(target, ignore_errors=True)
        return {'success': False, 'error': 'git clone failed: ' + (r.stderr or r.stdout)[:600]}

    if shallow and ref and re.match(r'^[0-9a-f]{7,40}$', ref):
        try:
            f = subprocess.run(
                ['git', '-C', target, 'fetch', '--depth', '1', 'origin', ref],
                capture_output=True, text=True, timeout=timeout_s,
            )
            if f.returncode != 0:
                subprocess.run(['git', '-C', target, 'fetch', '--unshallow'],
                               capture_output=True, text=True, timeout=timeout_s)
            co = subprocess.run(['git', '-C', target, 'checkout', ref],
                                capture_output=True, text=True, timeout=30)
            if co.returncode != 0:
                return {'success': False, 'error': 'checkout ' + ref + ' failed: ' + (co.stderr or co.stdout)[:400], 'path': target}
        except Exception as e:
            return {'success': False, 'error': 'fetch/checkout failed: ' + str(e), 'path': target}

    def dir_size_mb(p):
        total = 0
        for root, dirs, files in os.walk(p):
            for f in files:
                try:
                    total += os.path.getsize(os.path.join(root, f))
                except OSError:
                    pass
        return total / (1024 * 1024)
    size_mb = dir_size_mb(target)
    if size_mb > size_limit_mb:
        shutil.rmtree(target, ignore_errors=True)
        return {'success': False, 'error': 'clone exceeded size_limit_mb=' + str(size_limit_mb) + ' (was ' + str(round(size_mb, 1)) + ' MB)'}

    try:
        sha_r = subprocess.run(['git', '-C', target, 'rev-parse', 'HEAD'],
                               capture_output=True, text=True, timeout=10)
        head_sha = sha_r.stdout.strip() if sha_r.returncode == 0 else None
        br_r = subprocess.run(['git', '-C', target, 'rev-parse', '--abbrev-ref', 'HEAD'],
                              capture_output=True, text=True, timeout=10)
        branch = br_r.stdout.strip() if br_r.returncode == 0 else None
    except Exception:
        head_sha, branch = None, None

    file_count = 0
    for root, dirs, files in os.walk(target):
        if '.git' in dirs:
            dirs.remove('.git')
        file_count += len(files)

    return {
        'success': True,
        'cached': False,
        'repo': repo,
        'clone_url': clone_url,
        'path': target,
        'ref': ref or 'default',
        'head_sha': head_sha,
        'branch': branch,
        'file_count': file_count,
        'size_mb': round(size_mb, 2),
        'shallow': bool(shallow),
        'note': 'Clone is in the shared workspace. Use list_directory(path=...) to browse, read_file(filePath=...) to open, find_patterns on content, git_list_tree / git_log / git_show_commit / git_file_history / git_blame for git ops.',
    }

def execute(params):
    import subprocess, os
    repo_path = params.get('repoPath') or params.get('path_repo') or os.getcwd()
    if not os.path.isdir(repo_path):
        return {'success': False, 'error': 'repoPath not a directory: ' + str(repo_path)}
    ref = (params.get('ref') or 'HEAD').strip()
    sub_path = (params.get('path') or '').strip('/')
    recursive = True if params.get('recursive') is None else bool(params.get('recursive'))
    limit = int(params.get('limit') or 1000)
    if sub_path:
        if sub_path.startswith('/'):
            rp = os.sub_path.realpath(repo_path).rstrip('/')
            pp = os.sub_path.realpath(sub_path)
            if pp == rp:
                sub_path = '.'
            elif pp.startswith(rp + '/'):
                sub_path = pp[len(rp) + 1:]
            else:
                return {'success': False, 'error': 'sub_path must be repo-relative (e.g. "src/app.py" or "."), not absolute: ' + sub_path}
    cmd = ['git', '-C', repo_path, 'ls-tree', '--long']
    if recursive:
        cmd.append('-r')
    cmd.append(ref)
    if sub_path:
        cmd.append(sub_path)
    try:
        r = subprocess.run(cmd, capture_output=True, text=True, timeout=60)
    except Exception as e:
        return {'success': False, 'error': 'ls-tree failed: ' + str(e)}
    if r.returncode != 0:
        return {'success': False, 'error': 'ls-tree: ' + (r.stderr or r.stdout)[:400]}
    entries = []
    for line in r.stdout.splitlines():
        # Format with --long: "<mode> <type> <sha> <size|-> \t<path>"
        if not line:
            continue
        try:
            meta, path = line.split('\t', 1)
            parts = meta.split()
            mode, obj_type, sha = parts[0], parts[1], parts[2]
            size = parts[3] if len(parts) > 3 else None
            try:
                size = int(size)
            except Exception:
                size = None
            entries.append({
                'path': path,
                'type': ('dir' if obj_type == 'tree' else 'file'),
                'mode': mode,
                'sha': sha[:10],
                'size': size,
            })
        except Exception:
            continue
    total = len(entries)
    truncated = total > limit
    return {
        'success': True,
        'repoPath': repo_path,
        'ref': ref,
        'root': sub_path or '/',
        'recursive': bool(recursive),
        'total': total,
        'count': min(total, limit),
        'truncated': truncated,
        'entries': entries[:limit],
    }

def execute(params):
    import subprocess, os, re
    repo_path = params.get('repoPath') or os.getcwd()
    sha = (params.get('sha') or params.get('commit') or '').strip()
    if not sha:
        return {'success': False, 'error': 'sha required'}
    if not os.path.isdir(repo_path):
        return {'success': False, 'error': 'repoPath not a directory: ' + str(repo_path)}
    include_patches = True if params.get('include_patches') is None else bool(params.get('include_patches'))
    max_patch = int(params.get('max_patch_chars') or 8000)

    # 1) Metadata via --pretty
    try:
        meta = subprocess.run(
            ['git', '-C', repo_path, 'show', '--no-patch', '--pretty=format:%H%n%an%n%ae%n%at%n%cn%n%ct%n%P%n%s%n%b%n---END---', sha],
            capture_output=True, text=True, timeout=30,
        )
    except Exception as e:
        return {'success': False, 'error': 'show failed: ' + str(e)}
    if meta.returncode != 0:
        return {'success': False, 'error': 'git show: ' + (meta.stderr or meta.stdout)[:400]}
    lines = meta.stdout.split('\n')
    # Subject is line index 7; body may span multiple lines until ---END---
    try:
        full_sha = lines[0]
        author = lines[1]
        author_email = lines[2]
        author_ts = int(lines[3]) if lines[3] else None
        committer = lines[4]
        committer_ts = int(lines[5]) if lines[5] else None
        parents = lines[6].split() if lines[6] else []
        subject = lines[7]
        body_lines = []
        for l in lines[8:]:
            if l == '---END---':
                break
            body_lines.append(l)
        body = '\n'.join(body_lines).strip()
    except IndexError:
        return {'success': False, 'error': 'could not parse git show output'}

    # 2) Per-file stats via --numstat
    try:
        ns = subprocess.run(
            ['git', '-C', repo_path, 'log', '-n', '1', '--numstat', '--format=', sha],
            capture_output=True, text=True, timeout=30,
        )
    except Exception as e:
        return {'success': False, 'error': 'numstat failed: ' + str(e)}
    files_map = {}  # path -> {additions, deletions}
    for line in ns.stdout.splitlines():
        if not line.strip():
            continue
        parts = line.split('\t')
        if len(parts) < 3:
            continue
        add, dele, path = parts[0], parts[1], parts[2]
        try:
            add = int(add) if add != '-' else None
            dele = int(dele) if dele != '-' else None
        except Exception:
            add, dele = None, None
        files_map[path] = {'filename': path, 'additions': add, 'deletions': dele, 'patch': None, 'patch_truncated': False}

    # 3) Patches (optional)
    if include_patches:
        try:
            pr = subprocess.run(
                ['git', '-C', repo_path, 'show', '--format=', sha],
                capture_output=True, text=True, timeout=60,
            )
            if pr.returncode == 0:
                current = None
                buf = []
                def flush():
                    if current and buf:
                        p = '\n'.join(buf)
                        truncated = False
                        if len(p) > max_patch:
                            p = p[:max_patch] + '\n... (truncated)'
                            truncated = True
                        if current in files_map:
                            files_map[current]['patch'] = p
                            files_map[current]['patch_truncated'] = truncated
                for line in pr.stdout.splitlines():
                    m = re.match(r'^diff --git a/(.+) b/(.+)$', line)
                    if m:
                        flush()
                        current = m.group(2)
                        buf = [line]
                    else:
                        buf.append(line)
                flush()
        except Exception:
            pass  # patches optional

    files = list(files_map.values())
    total_add = sum((f.get('additions') or 0) for f in files)
    total_del = sum((f.get('deletions') or 0) for f in files)
    return {
        'success': True,
        'repoPath': repo_path,
        'sha': full_sha,
        'short_sha': full_sha[:10],
        'subject': subject,
        'body': body,
        'author': author,
        'author_email': author_email,
        'author_unix': author_ts,
        'committer': committer,
        'committer_unix': committer_ts,
        'parents': parents,
        'stats': {'total_additions': total_add, 'total_deletions': total_del, 'files_changed': len(files)},
        'files': files,
    }

def execute(params):
    import subprocess, os
    repo_path = params.get('repoPath') or os.getcwd()
    path = (params.get('path') or '').strip()
    if not path:
        return {'success': False, 'error': 'path required'}
    if not os.path.isdir(repo_path):
        return {'success': False, 'error': 'repoPath not a directory: ' + str(repo_path)}
    limit = int(params.get('limit') or 30)
    ref = (params.get('ref') or '').strip()
    follow = True if params.get('follow') is None else bool(params.get('follow'))
    if path:
        if path.startswith('/'):
            rp = os.path.realpath(repo_path).rstrip('/')
            pp = os.path.realpath(path)
            if pp == rp:
                path = '.'
            elif pp.startswith(rp + '/'):
                path = pp[len(rp) + 1:]
            else:
                return {'success': False, 'error': 'path must be repo-relative (e.g. "src/app.py" or "."), not absolute: ' + path}
    cmd = ['git', '-C', repo_path, 'log', '--pretty=format:%H%x1f%an%x1f%ae%x1f%at%x1f%s', '-' + str(limit)]
    if follow:
        cmd.append('--follow')
    if ref:
        cmd.append(ref)
    cmd += ['--', path]
    try:
        r = subprocess.run(cmd, capture_output=True, text=True, timeout=60)
    except Exception as e:
        return {'success': False, 'error': 'log failed: ' + str(e)}
    if r.returncode != 0:
        return {'success': False, 'error': 'git log: ' + (r.stderr or r.stdout)[:400]}
    commits = []
    for line in r.stdout.splitlines():
        if not line:
            continue
        parts = line.split('\x1f')
        if len(parts) < 5:
            continue
        try:
            ts = int(parts[3])
        except Exception:
            ts = None
        commits.append({
            'sha': parts[0][:10],
            'full_sha': parts[0],
            'author': parts[1],
            'email': parts[2],
            'unix': ts,
            'subject': parts[4],
        })
    return {
        'success': True,
        'repoPath': repo_path,
        'path': path,
        'follow_renames': follow,
        'ref': ref or 'HEAD',
        'count': len(commits),
        'commits': commits,
    }

def execute(params):
    import subprocess, os, re
    repo_path = params.get('repoPath') or os.getcwd()
    path = (params.get('path') or '').strip()
    if not path:
        return {'success': False, 'error': 'path required'}
    if not os.path.isdir(repo_path):
        return {'success': False, 'error': 'repoPath not a directory: ' + str(repo_path)}
    ref = (params.get('ref') or '').strip()
    line_start = params.get('line_start')
    line_end = params.get('line_end')
    max_lines = int(params.get('max_lines') or 500)
    if path:
        if path.startswith('/'):
            rp = os.path.realpath(repo_path).rstrip('/')
            pp = os.path.realpath(path)
            if pp == rp:
                path = '.'
            elif pp.startswith(rp + '/'):
                path = pp[len(rp) + 1:]
            else:
                return {'success': False, 'error': 'path must be repo-relative (e.g. "src/app.py" or "."), not absolute: ' + path}
    cmd = ['git', '-C', repo_path, 'blame', '--line-porcelain']
    if line_start and line_end:
        cmd += ['-L', str(line_start) + ',' + str(line_end)]
    elif line_start:
        cmd += ['-L', str(line_start) + ',+' + str(max_lines)]
    if ref:
        cmd.append(ref)
    cmd += ['--', path]
    try:
        r = subprocess.run(cmd, capture_output=True, text=True, timeout=60)
    except Exception as e:
        return {'success': False, 'error': 'blame failed: ' + str(e)}
    if r.returncode != 0:
        return {'success': False, 'error': 'git blame: ' + (r.stderr or r.stdout)[:400]}

    # Parse --line-porcelain: each line-block starts with "<sha> <orig-line> <final-line> <count>"
    # followed by header fields and a "\t<actual line>".
    lines = []
    commits_seen = {}
    cur = None
    for ln in r.stdout.splitlines():
        m = re.match(r'^([0-9a-f]{40})\s+(\d+)\s+(\d+)', ln)
        if m:
            cur = {'sha': m.group(1)[:10], 'full_sha': m.group(1),
                   'source_line': int(m.group(2)), 'final_line': int(m.group(3)),
                   'author': None, 'author_mail': None, 'author_time': None, 'summary': None, 'content': None}
            continue
        if cur is None:
            continue
        if ln.startswith('author '):
            cur['author'] = ln[7:]
        elif ln.startswith('author-mail '):
            cur['author_mail'] = ln[12:].strip('<>')
        elif ln.startswith('author-time '):
            try:
                cur['author_time'] = int(ln[12:])
            except Exception:
                pass
        elif ln.startswith('summary '):
            cur['summary'] = ln[8:]
        elif ln.startswith('\t'):
            cur['content'] = ln[1:]
            lines.append(cur)
            commits_seen.setdefault(cur['full_sha'], {'sha': cur['sha'], 'author': cur['author'], 'summary': cur['summary']})
            cur = None
    truncated = False
    if len(lines) > max_lines:
        lines = lines[:max_lines]
        truncated = True
    return {
        'success': True,
        'repoPath': repo_path,
        'path': path,
        'ref': ref or 'HEAD',
        'line_start': line_start,
        'line_end': line_end,
        'count': len(lines),
        'truncated': truncated,
        'unique_commits': len(commits_seen),
        'lines': lines,
    }

def execute(params):
    """Recursively grep file contents for a pattern."""
    import os, re, fnmatch

    # Default to USER_WORKSPACE (the sandbox bind mount) rather than '.' so
    # the skill doesn't end up grepping the harness's own /work cwd when the
    # model omits the directory arg. sandboxRunner only rewrites a param if
    # it's PRESENT, so a missing `directory` skipped the rewrite entirely
    # and the literal '.' below scanned only skill.py + params.json.
    workspace = os.environ.get('USER_WORKSPACE') or '/workspace'
    directory = params.get('directory') or params.get('dirPath') or workspace
    pattern = params.get('pattern')
    if pattern is None or pattern == '':
        return {'success': False, 'error': 'pattern parameter is required'}
    use_regex = bool(params.get('regex', False))
    file_pattern = params.get('filePattern') or params.get('glob') or '*'
    ignore_case = bool(params.get('ignoreCase', False))
    context = int(params.get('context') or 0)
    max_results = int(params.get('maxResults') or 200)
    # Exclude pip caches and other dep dirs by default so a search of
    # /workspace isn't drowned by yt_dlp / scikit-learn etc. installed
    # under /workspace/.deps. Override with `excludeDirs: []` to scan all.
    exclude_dirs = params.get('excludeDirs')
    if exclude_dirs is None:
        exclude_dirs = ['.git', 'node_modules', '__pycache__', '.venv', 'venv',
                        'dist', 'build', '.next', '.cache', '.build-state',
                        '.deps', '.npm', 'coverage', 'target', 'vendor',
                        '__pypackages__', '.tox', '.pytest_cache', '.mypy_cache']
    exclude_dirs = set(exclude_dirs)

    if not os.path.isdir(directory):
        # Likely the model passed an absolute path outside /workspace that
        # got rerouted to /workspace/<basename> by the sandbox path normalizer.
        # Surface the workspace constraint so the model corrects on the next
        # turn instead of retrying the same outside-workspace path.
        return {'success': False,
                'error': 'directory not found: ' + str(directory) +
                         ' (sandbox sees only /workspace; pass /workspace or'
                         ' a path relative to it)'}

    flags = re.IGNORECASE if ignore_case else 0
    if use_regex:
        try:
            rx = re.compile(pattern, flags)
        except re.error as e:
            return {'success': False, 'error': 'invalid regex: ' + str(e)}
    else:
        rx = re.compile(re.escape(pattern), flags)

    hits = []
    truncated = False
    files_scanned = 0
    for root, dirs, files in os.walk(directory):
        dirs[:] = [d for d in dirs if d not in exclude_dirs and not d.startswith('.git')]
        for fname in files:
            if not fnmatch.fnmatch(fname, file_pattern):
                continue
            full = os.path.join(root, fname)
            try:
                if os.path.getsize(full) > 5 * 1024 * 1024:
                    continue
                with open(full, 'r', encoding='utf-8', errors='replace') as f:
                    lines = f.readlines()
            except Exception:
                continue
            files_scanned += 1
            for i, ln in enumerate(lines):
                if rx.search(ln):
                    hit = {'path': full, 'line': i + 1, 'text': ln.rstrip('\n')}
                    if context > 0:
                        s = max(0, i - context)
                        e = min(len(lines), i + context + 1)
                        hit['context'] = ''.join(lines[s:e]).rstrip('\n')
                        hit['contextStart'] = s + 1
                    hits.append(hit)
                    if len(hits) >= max_results:
                        truncated = True
                        break
            if truncated:
                break
        if truncated:
            break

    return {'success': True, 'pattern': pattern, 'directory': directory,
            'filesScanned': files_scanned, 'count': len(hits),
            'truncated': truncated, 'hits': hits}

def execute(params):
    """Replace a specific line range in a file."""
    import os

    file_path = params.get('filePath') or params.get('path')
    if not file_path:
        return {'success': False, 'error': 'filePath parameter is required'}
    if not os.path.isfile(file_path):
        return {'success': False, 'error': 'file not found: ' + file_path + ' (sandbox sees only /workspace; pass /workspace/<file> or a path relative to it)'}

    start_line = params.get('startLine')
    end_line = params.get('endLine')
    new_content = params.get('newContent', '')

    if start_line is None:
        return {'success': False, 'error': 'startLine parameter is required'}
    try:
        start_line = int(start_line)
        end_line = int(end_line) if end_line is not None else start_line
    except (TypeError, ValueError):
        return {'success': False, 'error': 'startLine and endLine must be integers'}
    if start_line < 1:
        return {'success': False, 'error': 'startLine must be >= 1'}

    try:
        with open(file_path, 'r', encoding='utf-8') as f:
            lines = f.readlines()
    except Exception as e:
        return {'success': False, 'error': str(e)}

    original_count = len(lines)

    # Insert mode: startLine == endLine + 1 means insert at startLine without removing anything
    is_insert = end_line == start_line - 1
    if not is_insert and end_line < start_line:
        return {'success': False, 'error': 'endLine must be >= startLine (or startLine - 1 for insert mode)'}
    if start_line > original_count + 1:
        return {'success': False, 'error': 'startLine ' + str(start_line) + ' exceeds file length ' + str(original_count)}

    # Normalize newContent to end with newline
    new_lines = new_content.splitlines(keepends=True)
    if new_lines and not new_lines[-1].endswith('\n'):
        new_lines[-1] += '\n'
    elif not new_lines and not is_insert:
        # Empty replacement = pure delete
        pass

    if is_insert:
        result = lines[:start_line - 1] + new_lines + lines[start_line - 1:]
        replaced_count = 0
    else:
        result = lines[:start_line - 1] + new_lines + lines[end_line:]
        replaced_count = end_line - start_line + 1

    try:
        with open(file_path, 'w', encoding='utf-8') as f:
            f.writelines(result)
    except Exception as e:
        return {'success': False, 'error': 'write failed: ' + str(e)}

    preview_start = max(0, start_line - 2)
    preview_end = min(len(result), start_line - 1 + len(new_lines) + 1)
    preview = ''.join('{:>5}: {}'.format(i + 1, result[i]) for i in range(preview_start, preview_end))

    return {
        'success': True,
        'filePath': file_path,
        'mode': 'insert' if is_insert else 'replace',
        'linesReplaced': replaced_count,
        'linesAdded': len(new_lines),
        'originalLineCount': original_count,
        'newLineCount': len(result),
        'preview': preview
    }

def execute(params):
    '''Extract text/elements from HTML using CSS selectors.'''
    html = params.get('html') or params.get('htmlString') or params.get('content')
    if not html or not isinstance(html, str):
        return {'success': False, 'error': 'html parameter is required (string)'}
    selector = params.get('selector') or params.get('cssSelector')
    attribute = params.get('attribute')   # if set, return this attr instead of text
    limit = int(params.get('limit') or 50)
    try:
        from bs4 import BeautifulSoup
    except ImportError:
        return {'success': False, 'error': 'BeautifulSoup (bs4) is not installed in the webapp image'}
    try:
        soup = BeautifulSoup(html, 'lxml')
    except Exception:
        soup = BeautifulSoup(html, 'html.parser')

    title = (soup.title.string.strip() if soup.title and soup.title.string else None)
    meta = {}
    for m in soup.find_all('meta'):
        k = m.get('name') or m.get('property')
        v = m.get('content')
        if k and v and k not in meta:
            meta[k] = v[:500]
    links = []
    for a in soup.find_all('a', href=True)[:limit]:
        links.append({'text': (a.get_text(strip=True) or '')[:200], 'href': a['href']})

    if selector:
        try:
            els = soup.select(selector)[:limit]
        except Exception as e:
            return {'success': False, 'error': f'Invalid selector: {e}'}
        out = []
        for el in els:
            if attribute:
                out.append(el.get(attribute))
            else:
                out.append({
                    'tag': el.name,
                    'text': el.get_text(' ', strip=True)[:1000],
                    'attrs': {k: (v if isinstance(v, str) else ' '.join(v))[:200] for k, v in el.attrs.items()},
                })
        return {'success': True, 'selector': selector, 'matchCount': len(out), 'matches': out,
                'title': title, 'meta': meta}

    text = soup.get_text(' ', strip=True)
    if len(text) > 12000:
        text = text[:12000] + '... [truncated]'
    return {'success': True, 'title': title, 'meta': meta, 'text': text,
            'linkCount': len(soup.find_all('a', href=True)), 'links': links}

def execute(params):
    '''Parse XML to a nested dict structure.'''
    xml = params.get('xml') or params.get('xmlString') or params.get('content')
    if not xml or not isinstance(xml, str):
        return {'success': False, 'error': 'xml parameter is required (string)'}
    import xml.etree.ElementTree as ET
    def to_dict(el):
        d = {}
        if el.attrib:
            d['@attrs'] = dict(el.attrib)
        children = list(el)
        if children:
            for c in children:
                cd = to_dict(c)
                tag = c.tag.split('}', 1)[-1]
                if tag in d:
                    if not isinstance(d[tag], list):
                        d[tag] = [d[tag]]
                    d[tag].append(cd)
                else:
                    d[tag] = cd
        text = (el.text or '').strip()
        if text:
            if d:
                d['#text'] = text
            else:
                return text
        return d if d else None
    try:
        root = ET.fromstring(xml)
    except ET.ParseError as e:
        return {'success': False, 'error': f'Invalid XML: {e}'}
    tag = root.tag.split('}', 1)[-1]
    return {'success': True, 'root': tag, 'data': {tag: to_dict(root)}}

def execute(params):
    '''Parse YAML to Python data structure.'''
    text = params.get('yaml') or params.get('yamlString') or params.get('content')
    if not text or not isinstance(text, str):
        return {'success': False, 'error': 'yaml parameter is required (string)'}
    try:
        import yaml
    except ImportError:
        return {'success': False, 'error': 'PyYAML is not installed in the webapp image'}
    try:
        docs = list(yaml.safe_load_all(text))
    except yaml.YAMLError as e:
        return {'success': False, 'error': f'Invalid YAML: {e}'}
    if len(docs) == 1:
        return {'success': True, 'data': docs[0], 'documents': 1}
    return {'success': True, 'data': docs, 'documents': len(docs)}

def execute(params):
    '''Parse TOML to dict.'''
    text = params.get('toml') or params.get('tomlString') or params.get('content')
    if not text or not isinstance(text, str):
        return {'success': False, 'error': 'toml parameter is required (string)'}
    try:
        import tomllib
    except ImportError:
        try:
            import tomli as tomllib
        except ImportError:
            return {'success': False, 'error': 'tomllib/tomli not available (need Python 3.11+)'}
    try:
        data = tomllib.loads(text)
    except Exception as e:
