def execute(params):
    '''Parse INI/conf-style configuration files.'''
    text = params.get('ini') or params.get('iniString') or params.get('content')
    if not text or not isinstance(text, str):
        return {'success': False, 'error': 'ini parameter is required (string)'}
    import configparser, io
    cp = configparser.ConfigParser(interpolation=None, strict=False)
    cp.optionxform = str
    try:
        cp.read_file(io.StringIO(text))
    except configparser.Error as e:
        return {'success': False, 'error': f'Invalid INI: {e}'}
    data = {s: dict(cp.items(s)) for s in cp.sections()}
    if cp.defaults():
        data['DEFAULT'] = dict(cp.defaults())
    return {'success': True, 'data': data, 'sections': list(data.keys())}

def execute(params):
    '''Decompose a URL into scheme, host, port, path, query params, fragment.'''
    url = params.get('url')
    if not url or not isinstance(url, str):
        return {'success': False, 'error': 'url parameter is required (string)'}
    from urllib.parse import urlparse, parse_qs
    try:
        u = urlparse(url)
    except Exception as e:
        return {'success': False, 'error': f'Invalid URL: {e}'}
    return {
        'success': True,
        'scheme': u.scheme,
        'username': u.username,
        'password': '***' if u.password else None,
        'host': u.hostname,
        'port': u.port,
        'path': u.path,
        'query': u.query,
        'queryParams': {k: v if len(v) > 1 else v[0] for k, v in parse_qs(u.query, keep_blank_values=True).items()},
        'fragment': u.fragment,
    }

def execute(params):
    '''Parse a query string (e.g., "a=1&b=2&b=3") into a dict.'''
    qs = params.get('queryString') or params.get('query') or params.get('content')
    if qs is None or not isinstance(qs, str):
        return {'success': False, 'error': 'queryString parameter is required (string)'}
    from urllib.parse import parse_qs
    qs = qs.lstrip('?')
    parsed = parse_qs(qs, keep_blank_values=True)
    flat = {k: (v[0] if len(v) == 1 else v) for k, v in parsed.items()}
    return {'success': True, 'data': flat, 'raw': parsed, 'paramCount': len(flat)}

def execute(params):
    '''Decode a JWT (header + payload, NO signature verification).'''
    token = params.get('jwt') or params.get('token')
    if not token or not isinstance(token, str):
        return {'success': False, 'error': 'jwt parameter is required (string)'}
    import base64, json
    parts = token.strip().split('.')
    if len(parts) < 2:
        return {'success': False, 'error': 'Not a JWT (expected 3 dot-separated parts)'}
    def b64url(s):
        s += '=' * ((4 - len(s) % 4) % 4)
        return base64.urlsafe_b64decode(s)
    try:
        header = json.loads(b64url(parts[0]))
        payload = json.loads(b64url(parts[1]))
    except Exception as e:
        return {'success': False, 'error': f'Invalid JWT encoding: {e}'}
    notes = []
    import time
    now = int(time.time())
    if 'exp' in payload:
        notes.append(f"exp in {payload['exp']-now}s ({'EXPIRED' if payload['exp']<now else 'valid'})")
    if 'iat' in payload:
        notes.append(f"issued {now-payload['iat']}s ago")
    return {
        'success': True,
        'header': header,
        'payload': payload,
        'signaturePresent': len(parts) == 3 and bool(parts[2]),
        'verified': False,
        'notes': '; '.join(notes) if notes else None,
    }

def execute(params):
    '''Heuristic User-Agent string parser (browser, OS, device).'''
    ua = params.get('userAgent') or params.get('ua') or params.get('content')
    if not ua or not isinstance(ua, str):
        return {'success': False, 'error': 'userAgent parameter is required (string)'}
    import re
    s = ua
    out = {'raw': s, 'browser': None, 'browserVersion': None, 'os': None, 'osVersion': None, 'device': 'desktop', 'isBot': False}
    if re.search(r'bot|crawler|spider|slurp|facebookexternalhit|preview', s, re.I):
        out['isBot'] = True; out['device'] = 'bot'
    if re.search(r'iPhone|iPad|Android.*Mobile|Mobile.*Android|Windows Phone', s):
        out['device'] = 'mobile'
    elif re.search(r'iPad|Tablet|Android(?!.*Mobile)', s):
        out['device'] = 'tablet'
    browsers = [
        ('Edge', r'Edg(?:e|A|iOS)?/([0-9.]+)'),
        ('Opera', r'OPR/([0-9.]+)'),
        ('Chrome', r'Chrome/([0-9.]+)'),
        ('Firefox', r'Firefox/([0-9.]+)'),
        ('Safari', r'Version/([0-9.]+).*Safari'),
        ('IE', r'(?:MSIE |rv:)([0-9.]+).*Trident'),
        ('curl', r'curl/([0-9.]+)'),
        ('wget', r'Wget/([0-9.]+)'),
        ('Python-requests', r'python-requests/([0-9.]+)'),
    ]
    for name, pat in browsers:
        m = re.search(pat, s)
        if m:
            out['browser'] = name; out['browserVersion'] = m.group(1); break
    oses = [
        ('Windows', r'Windows NT ([0-9.]+)'),
        ('macOS', r'Mac OS X ([0-9_.]+)'),
        ('iOS', r'(?:iPhone|iPad).*OS ([0-9_.]+)'),
        ('Android', r'Android ([0-9.]+)'),
        ('Linux', r'(Linux)'),
    ]
    for name, pat in oses:
        m = re.search(pat, s)
        if m:
            out['os'] = name
            try:
                out['osVersion'] = m.group(1).replace('_', '.')
            except IndexError:
                pass
            break
    return {'success': True, **out}

def execute(params):
    '''Parse a Cookie or Set-Cookie header string.'''
    text = params.get('cookie') or params.get('header') or params.get('content')
    if not text or not isinstance(text, str):
        return {'success': False, 'error': 'cookie parameter is required (string)'}
    # Set-Cookie has attributes (Path, Expires, etc.) — split on comma carefully.
    # Heuristic: if 'Path=' or 'Domain=' or 'Expires=' present, treat as Set-Cookie.
    if any(k in text for k in ('Path=', 'Domain=', 'Expires=', 'Max-Age=', 'HttpOnly', 'Secure', 'SameSite=')):
        # crude: each Set-Cookie entry separated by comma but commas can appear in Expires date
        # split on '\n' first, then attempt comma split keeping date intact
        entries = []
        for line in text.split('\n'):
            line = line.strip()
            if not line: continue
            # split on ", " not preceded by a weekday
            import re
            parts = re.split(r',(?!\s*(?:Mon|Tue|Wed|Thu|Fri|Sat|Sun))', line)
            for p in parts:
                p = p.strip()
                if not p: continue
                segs = [s.strip() for s in p.split(';')]
                kv = segs[0].split('=', 1)
                cookie = {'name': kv[0], 'value': kv[1] if len(kv) > 1 else ''}
                for s in segs[1:]:
                    if '=' in s:
                        k, v = s.split('=', 1)
                        cookie[k.strip()] = v.strip()
                    else:
                        cookie[s.strip()] = True
                entries.append(cookie)
        return {'success': True, 'type': 'Set-Cookie', 'cookies': entries, 'count': len(entries)}
    # Plain Cookie header: name=value; name=value
    out = {}
    for seg in text.split(';'):
        seg = seg.strip()
        if not seg: continue
        if '=' in seg:
            k, v = seg.split('=', 1)
            out[k.strip()] = v.strip()
        else:
            out[seg] = ''
    return {'success': True, 'type': 'Cookie', 'cookies': out, 'count': len(out)}

def execute(params):
    '''Parse a raw RFC822 email message into headers, body, attachments.'''
    text = params.get('email') or params.get('raw') or params.get('content')
    if not text or not isinstance(text, str):
        return {'success': False, 'error': 'email parameter is required (raw RFC822 string)'}
    import email
    from email import policy
    try:
        msg = email.message_from_string(text, policy=policy.default)
    except Exception as e:
        return {'success': False, 'error': f'Failed to parse: {e}'}
    headers = {k: msg[k] for k in ('From','To','Cc','Bcc','Subject','Date','Message-ID','Reply-To','Return-Path') if msg[k]}
    text_body = None
    html_body = None
    attachments = []
    if msg.is_multipart():
        for part in msg.walk():
            ct = part.get_content_type()
            disp = (part.get('Content-Disposition') or '').lower()
            if 'attachment' in disp or part.get_filename():
                attachments.append({'filename': part.get_filename(), 'contentType': ct,
                                    'size': len(part.get_payload(decode=True) or b'')})
                continue
            if ct == 'text/plain' and text_body is None:
                try: text_body = part.get_content()
                except Exception: pass
            elif ct == 'text/html' and html_body is None:
                try: html_body = part.get_content()
                except Exception: pass
    else:
        try: text_body = msg.get_content()
        except Exception: text_body = msg.get_payload()
    if text_body and len(text_body) > 12000:
        text_body = text_body[:12000] + '... [truncated]'
    if html_body and len(html_body) > 12000:
        html_body = html_body[:12000] + '... [truncated]'
    return {'success': True, 'headers': headers, 'allHeaders': dict(msg.items()),
            'text': text_body, 'html': html_body, 'attachments': attachments,
            'attachmentCount': len(attachments)}

def execute(params):
    '''Parse a unified diff into per-file hunks with added/removed counts.'''
    text = params.get('diff') or params.get('content')
    if not text or not isinstance(text, str):
        return {'success': False, 'error': 'diff parameter is required (string)'}
    files = []
    cur = None
    cur_hunk = None
    for line in text.split('\n'):
        if line.startswith('diff --git') or (line.startswith('--- ') and not line.startswith('---  ')):
            if cur is not None:
                if cur_hunk: cur['hunks'].append(cur_hunk); cur_hunk = None
                files.append(cur)
            cur = {'header': line, 'fromFile': None, 'toFile': None, 'added': 0, 'removed': 0, 'hunks': []}
            if line.startswith('--- '):
                cur['fromFile'] = line[4:].strip()
        elif line.startswith('+++ ') and cur is not None:
            cur['toFile'] = line[4:].strip()
        elif line.startswith('@@') and cur is not None:
            if cur_hunk: cur['hunks'].append(cur_hunk)
            cur_hunk = {'header': line, 'lines': []}
        elif cur is not None and cur_hunk is not None:
            if line.startswith('+') and not line.startswith('+++'):
                cur['added'] += 1
            elif line.startswith('-') and not line.startswith('---'):
                cur['removed'] += 1
            cur_hunk['lines'].append(line)
    if cur is not None:
        if cur_hunk: cur['hunks'].append(cur_hunk)
        files.append(cur)
    total_added = sum(f['added'] for f in files)
    total_removed = sum(f['removed'] for f in files)
    # Trim hunk lines so the response stays compact
    for f in files:
        f['hunkCount'] = len(f['hunks'])
        for h in f['hunks']:
            if len(h['lines']) > 60:
                h['lines'] = h['lines'][:60] + ['... [truncated]']
    return {'success': True, 'fileCount': len(files), 'totalAdded': total_added,
            'totalRemoved': total_removed, 'files': files}

def execute(params):
    '''Parse an IP address or CIDR. Returns version, network, broadcast, host count.'''
    s = params.get('ip') or params.get('cidr') or params.get('address') or params.get('content')
    if not s or not isinstance(s, str):
        return {'success': False, 'error': 'ip parameter is required (string)'}
    s = s.strip()
    import ipaddress
    try:
        if '/' in s:
            net = ipaddress.ip_network(s, strict=False)
            hosts = net.num_addresses
            return {'success': True, 'kind': 'network', 'version': net.version,
                    'cidr': str(net), 'networkAddress': str(net.network_address),
                    'broadcastAddress': str(net.broadcast_address) if net.version == 4 else None,
                    'netmask': str(net.netmask), 'prefixLength': net.prefixlen,
                    'numAddresses': hosts, 'isPrivate': net.is_private,
                    'isGlobal': net.is_global, 'isLoopback': net.is_loopback,
                    'firstHost': str(next(net.hosts(), net.network_address)) if hosts > 1 else str(net.network_address)}
        addr = ipaddress.ip_address(s)
        return {'success': True, 'kind': 'address', 'version': addr.version,
                'address': str(addr), 'isPrivate': addr.is_private,
                'isGlobal': addr.is_global, 'isLoopback': addr.is_loopback,
                'isMulticast': addr.is_multicast, 'isReserved': addr.is_reserved,
                'reverseDns': addr.reverse_pointer}
    except ValueError as e:
        return {'success': False, 'error': str(e)}

def execute(params):
    '''Parse a HAR (HTTP Archive) JSON and summarize entries.'''
    text = params.get('har') or params.get('content')
    if not text or not isinstance(text, str):
        return {'success': False, 'error': 'har parameter is required (JSON string)'}
    import json
    try:
        data = json.loads(text)
    except Exception as e:
        return {'success': False, 'error': f'Invalid JSON: {e}'}
    log = data.get('log') or {}
    entries = log.get('entries') or []
    summary = []
    status_counts = {}
    total_bytes = 0
    total_time = 0.0
    for e in entries:
        req = e.get('request') or {}
        resp = e.get('response') or {}
        status = resp.get('status')
        status_counts[status] = status_counts.get(status, 0) + 1
        size = (resp.get('content') or {}).get('size') or 0
        total_bytes += max(0, size)
        total_time += float(e.get('time') or 0)
        summary.append({
            'method': req.get('method'),
            'url': req.get('url'),
            'status': status,
            'mimeType': (resp.get('content') or {}).get('mimeType'),
            'size': size,
            'timeMs': e.get('time'),
        })
    return {'success': True, 'entryCount': len(entries),
            'totalBytes': total_bytes, 'totalTimeMs': round(total_time, 1),
            'statusCounts': status_counts,
            'creator': log.get('creator'),
            'entries': summary[:200],
            'truncated': len(summary) > 200}

def execute(params):
    '''Parse a PEM-encoded X.509 certificate and report subject, issuer, validity, SANs.'''
    pem = params.get('pem') or params.get('certificate') or params.get('content')
    if not pem or not isinstance(pem, str):
        return {'success': False, 'error': 'pem parameter is required (string)'}
    try:
        from cryptography import x509
        from cryptography.hazmat.backends import default_backend
    except ImportError:
        return {'success': False, 'error': 'cryptography module is not installed'}
    pem_bytes = pem.encode('utf-8')
    try:
        cert = x509.load_pem_x509_certificate(pem_bytes, default_backend())
    except Exception as e:
        return {'success': False, 'error': f'Failed to load certificate: {e}'}
    def name_to_dict(n):
        return {a.oid._name: a.value for a in n}
    sans = []
    try:
        ext = cert.extensions.get_extension_for_class(x509.SubjectAlternativeName)
        sans = [str(v) for v in ext.value]
    except x509.ExtensionNotFound:
        pass
    import datetime
    now = datetime.datetime.utcnow()
    not_before = cert.not_valid_before
    not_after = cert.not_valid_after
    return {
        'success': True,
        'subject': name_to_dict(cert.subject),
        'issuer': name_to_dict(cert.issuer),
        'serialNumber': format(cert.serial_number, 'x'),
        'notBefore': not_before.isoformat() + 'Z',
        'notAfter': not_after.isoformat() + 'Z',
        'expired': now > not_after,
        'daysUntilExpiry': (not_after - now).days,
        'subjectAltNames': sans,
        'signatureAlgorithm': cert.signature_algorithm_oid._name,
        'fingerprintSHA256': cert.fingerprint(__import__('cryptography.hazmat.primitives.hashes', fromlist=['SHA256']).SHA256()).hex(),
    }

def execute(params):
    '''Parse an XML sitemap or sitemapindex and extract URLs with metadata.'''
    text = params.get('sitemap') or params.get('xml') or params.get('content')
    if not text or not isinstance(text, str):
        return {'success': False, 'error': 'sitemap parameter is required (XML string)'}
    import xml.etree.ElementTree as ET, re
    text = re.sub(r'\sxmlns="[^"]+"', '', text, count=1)
    try:
        root = ET.fromstring(text)
    except ET.ParseError as e:
        return {'success': False, 'error': f'Invalid XML: {e}'}
    if root.tag.endswith('sitemapindex'):
        items = []
        for sm in root.findall('sitemap'):
            items.append({'loc': (sm.findtext('loc') or '').strip(),
                          'lastmod': (sm.findtext('lastmod') or '').strip() or None})
        return {'success': True, 'kind': 'sitemapindex', 'count': len(items), 'sitemaps': items[:500]}
    urls = []
    for u in root.findall('url'):
        urls.append({
            'loc': (u.findtext('loc') or '').strip(),
            'lastmod': (u.findtext('lastmod') or '').strip() or None,
            'changefreq': (u.findtext('changefreq') or '').strip() or None,
            'priority': (u.findtext('priority') or '').strip() or None,
        })
    return {'success': True, 'kind': 'urlset', 'count': len(urls),
            'urls': urls[:500], 'truncated': len(urls) > 500}

def execute(params):
    """Extract text from a PDF using pypdf. Returns concatenated page text."""
    import os
    try:
        from pypdf import PdfReader
    except ImportError:
        return {"success": False, "error": "pypdf not installed in this sandbox image"}
    file_path = params.get('filePath')
    if not file_path:
        return {"success": False, "error": "filePath is required"}
    if not os.path.exists(file_path):
        ws = os.environ.get('USER_WORKSPACE', '/workspace')
        hint = f" Files uploaded into chat live under {ws}/ — paths outside the workspace get rewritten to {ws}/<basename>; use list_directory({ws}) to see what is actually there."
        return {"success": False, "error": f"file not found: {file_path}." + hint}
    try:
        reader = PdfReader(file_path)
        if getattr(reader, 'is_encrypted', False):
            try:
                ok = reader.decrypt('')
            except Exception:
                ok = 0
            if not ok:
                return {"success": False, "error": "PDF is encrypted (password-protected); cannot extract"}
        page_count = len(reader.pages)
        max_pages = params.get('maxPages')
        try:
            limit = int(max_pages) if max_pages else page_count
        except (TypeError, ValueError):
            limit = page_count
        if limit <= 0:
            limit = page_count
        limit = min(limit, page_count)
        parts = []
        for i in range(limit):
            try:
                t = reader.pages[i].extract_text() or ''
            except Exception as e:
                t = f'[page {i+1}: extraction failed: {e}]'
            parts.append(t)
        text = '\n\n'.join(parts).strip()
        return {
            "success": True,
            "text": text,
            "pageCount": page_count,
            "pagesExtracted": limit,
            "charCount": len(text),
        }
    except Exception as e:
        return {"success": False, "error": f"PDF parse failed: {e}"}

