def execute(params):
    """Render PDF pages to images under /workspace/artifacts/ via pdf2image (poppler)."""
    import os, re
    try:
        from pdf2image import convert_from_path
    except ImportError:
        return {"success": False, "error": "pdf2image not installed in this sandbox image"}
    file_path = params.get('filePath')
    if not file_path:
        return {"success": False, "error": "filePath is required"}
    if not os.path.exists(file_path):
        ws = os.environ.get('USER_WORKSPACE', '/workspace')
        return {"success": False, "error": f"file not found: {file_path}. Files uploaded into chat live under {ws}/."}
    try:
        dpi = int(params.get('dpi') or 150)
    except (TypeError, ValueError):
        dpi = 150
    dpi = max(50, min(dpi, 400))
    fmt = str(params.get('format') or 'png').lower()
    if fmt == 'jpg':
        fmt = 'jpeg'
    if fmt not in ('png', 'jpeg'):
        fmt = 'png'
    artifacts_dir = '/workspace/artifacts'
    os.makedirs(artifacts_dir, exist_ok=True)
    base = re.sub(r'\W+', '_', os.path.splitext(os.path.basename(file_path))[0]) or 'pdf'
    kwargs = {'dpi': dpi, 'fmt': fmt}
    fp = params.get('firstPage')
    lp = params.get('lastPage')
    try:
        if fp is not None and int(fp) > 0:
            kwargs['first_page'] = int(fp)
    except (TypeError, ValueError):
        pass
    try:
        if lp is not None and int(lp) > 0:
            kwargs['last_page'] = int(lp)
    except (TypeError, ValueError):
        pass
    try:
        images = convert_from_path(file_path, **kwargs)
    except Exception as e:
        return {"success": False, "error": f"pdf2image failed: {e}"}
    ext = 'jpg' if fmt == 'jpeg' else 'png'
    pil_fmt = 'JPEG' if fmt == 'jpeg' else 'PNG'
    start = kwargs.get('first_page', 1)
    written = []
    for i, img in enumerate(images):
        out = os.path.join(artifacts_dir, f'{base}_page{start + i:03d}.{ext}')
        img.save(out, pil_fmt)
        written.append(out)
    return {
        "success": True,
        "files": written,
        "pageCount": len(written),
        "dpi": dpi,
        "format": ext,
    }

