def execute(params):
    """Persistent per-workspace SQLite collection (store / query / clear / schema).

    store with a `key` (field name) deduplicates: only records whose key wasn't
    seen before are inserted; returned in `new`. `keyStrip` (comma-separated
    words removed from the key, e.g. "NEW") and `keyNormalize` (lowercase +
    collapse punctuation/spacing) make the key a STABLE identity so re-listed /
    slightly-changed records don't leak back in as new.
    """
    import os, sqlite3, json, re

    action = str(params.get('action') or 'query').strip().lower()
    db = str(params.get('db') or params.get('path') or 'data.db').strip()
    if '..' in db.split('/'):
        return {'success': False, 'error': 'invalid db path'}
    if not re.search(r'\.(db|sqlite|sqlite3)$', db, re.I):
        db += '.db'
    table = str(params.get('table') or 'records').strip()
    if not re.match(r'^[A-Za-z_][A-Za-z0-9_]*$', table):
        return {'success': False, 'error': 'invalid table name (letters/digits/underscore, must start with a letter or underscore)'}

    path = db if os.path.isabs(db) else os.path.join('/workspace', db)
    parent = os.path.dirname(path)
    if parent:
        os.makedirs(parent, exist_ok=True)

    conn = sqlite3.connect(path)
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    cur.execute('CREATE TABLE IF NOT EXISTS "%s" (id INTEGER PRIMARY KEY AUTOINCREMENT, ts TEXT DEFAULT (datetime(\'now\')), k TEXT, data TEXT)' % table)
    existing = [r[1] for r in cur.execute('PRAGMA table_info("%s")' % table).fetchall()]
    if 'k' not in existing:
        cur.execute('ALTER TABLE "%s" ADD COLUMN k TEXT' % table)
    cur.execute('CREATE UNIQUE INDEX IF NOT EXISTS "%s_k_uniq" ON "%s"(k) WHERE k IS NOT NULL' % (table, table))
    conn.commit()

    keyfields = [f.strip() for f in str(params.get('key') or params.get('uniqueBy') or '').split(',') if f.strip()]
    keynorm = bool(params.get('keyNormalize'))
    strip_words = [w.strip() for w in str(params.get('keyStrip') or '').split(',') if w.strip()]

    def key_of(rec):
        if not keyfields:
            return None
        if isinstance(rec, dict):
            v = None
            for f in keyfields:
                val = rec.get(f)
                if val is not None and str(val).strip() != '':
                    v = val
                    break
        else:
            v = rec
        if v is None:
            return None
        k = str(v)
        for w in strip_words:
            k = re.sub(r'\b' + re.escape(w) + r'\b', '', k, flags=re.I)
        k = re.sub(r'[^a-z0-9]+', ' ', k.lower()).strip() if keynorm else k.strip()
        return k if k != '' else None

    try:
        if action == 'store':
            value = params.get('value')
            if value is None:
                value = params.get('data')
            records = value if isinstance(value, list) else [value]
            new_recs = []
            skipped = 0
            for rec in records:
                if rec is None:
                    continue
                k = key_of(rec)
                payload = rec if isinstance(rec, str) else json.dumps(rec, ensure_ascii=False)
                if k is not None:
                    cur.execute('INSERT OR IGNORE INTO "%s" (k, data) VALUES (?, ?)' % table, (k, payload))
                    if cur.rowcount == 1:
                        new_recs.append(rec)
                    else:
                        skipped += 1
                else:
                    cur.execute('INSERT INTO "%s" (data) VALUES (?)' % table, (payload,))
                    new_recs.append(rec)
            conn.commit()
            total = cur.execute('SELECT COUNT(*) AS c FROM "%s"' % table).fetchone()['c']
            return {'success': True, 'action': 'store', 'stored': len(new_recs), 'skipped': skipped, 'total': total, 'new': new_recs, 'table': table, 'db': db}

        if action in ('clear', 'reset'):
            cur.execute('DELETE FROM "%s"' % table)
            conn.commit()
            return {'success': True, 'action': 'clear', 'table': table, 'db': db}

        if action == 'schema':
            count = cur.execute('SELECT COUNT(*) AS c FROM "%s"' % table).fetchone()['c']
            sample = cur.execute('SELECT data FROM "%s" ORDER BY id DESC LIMIT 1' % table).fetchone()
            fields = []
            if sample:
                try:
                    obj = json.loads(sample['data'])
                    if isinstance(obj, dict):
                        fields = list(obj.keys())
                except Exception:
                    pass
            return {'success': True, 'action': 'schema', 'table': table, 'columns': existing or ['id', 'ts', 'k', 'data'], 'rowCount': count, 'recordFields': fields, 'db': db}

        sql = str(params.get('sql') or '').strip()
        if sql:
            m = re.search(r'```(?:sql)?\s*(.+?)```', sql, re.S | re.I)
            if m:
                sql = m.group(1).strip()
            m2 = re.search(r'((?:WITH|SELECT)\b.+)', sql, re.S | re.I)
            if m2:
                sql = m2.group(1).strip()
            sql = sql.rstrip(';').strip()
            if not re.match(r'^(WITH|SELECT)\b', sql, re.I):
                return {'success': False, 'error': 'only SELECT/WITH queries are allowed here'}
            cur.execute(sql, tuple(params.get('params') or []))
            colnames = [c[0] for c in cur.description] if cur.description else []
            rows = [{c: r[c] for c in colnames} for r in cur.fetchall()]
            if colnames == ['data']:
                parsed = []
                for row in rows:
                    try:
                        parsed.append(json.loads(row['data']))
                    except Exception:
                        parsed.append(row['data'])
                rows = parsed
            return {'success': True, 'action': 'query', 'count': len(rows), 'rows': rows, 'table': table, 'db': db}

        limit = int(params.get('limit') or 100)
        order = str(params.get('order') or 'id DESC').strip()
        if not re.match(r'^(id|ts)(\s+(asc|desc))?$', order, re.I):
            order = 'id DESC'
        cur.execute('SELECT id, ts, data FROM "%s" ORDER BY %s LIMIT ?' % (table, order), (limit,))
        recs = []
        for r in cur.fetchall():
            try:
                recs.append(json.loads(r['data']))
            except Exception:
                recs.append(r['data'])
        return {'success': True, 'action': 'query', 'count': len(recs), 'rows': recs, 'table': table, 'db': db}
    except Exception as e:
        return {'success': False, 'error': str(e)}
    finally:
        conn.close()

def execute(params):
    """Watch a single source (web page / API body / text) for changes BETWEEN runs and report the diff.

    Give a stable `key` (e.g. the page URL) and the current `content`. The latest
    snapshot per key is stored in a per-workspace SQLite db; on the next run, if
    the content differs, returns changed=True with a unified diff plus the added/
    removed lines and a revision number. First sighting stores a baseline
    (changed=False) so nothing fires until there is a real change.
    """
    import os, sqlite3, json, re, hashlib, difflib

    db = str(params.get('db') or 'automation.db').strip()
    if '..' in db.split('/'):
        return {'success': False, 'error': 'invalid db path'}
    if not re.search(r'\.(db|sqlite|sqlite3)$', db, re.I):
        db += '.db'
    table = str(params.get('table') or 'snapshots').strip()
    if not re.match(r'^[A-Za-z_][A-Za-z0-9_]*$', table):
        return {'success': False, 'error': 'invalid table name'}
    key = str(params.get('key') or 'default').strip() or 'default'

    content = params.get('content')
    if content is None:
        content = ''
    if not isinstance(content, str):
        try:
            content = json.dumps(content, ensure_ascii=False, sort_keys=True, indent=2)
        except Exception:
            content = str(content)

    action = str(params.get('action') or 'track').strip().lower()
    ignore_ws = bool(params.get('ignoreWhitespace'))

    path = db if os.path.isabs(db) else os.path.join('/workspace', db)
    parent = os.path.dirname(path)
    if parent:
        os.makedirs(parent, exist_ok=True)
    conn = sqlite3.connect(path)
    cur = conn.cursor()
    cur.execute('CREATE TABLE IF NOT EXISTS "%s" (k TEXT PRIMARY KEY, content TEXT, hash TEXT, revision INTEGER DEFAULT 1, created TEXT DEFAULT (datetime(\'now\')), updated TEXT DEFAULT (datetime(\'now\')))' % table)
    try:
        if action in ('reset', 'clear'):
            if action == 'clear':
                cur.execute('DELETE FROM "%s"' % table)
            else:
                cur.execute('DELETE FROM "%s" WHERE k=?' % table, (key,))
            conn.commit()
            return {'success': True, 'reset': True, 'cleared': action == 'clear', 'key': key}

        def canon(s):
            return re.sub(r'\s+', ' ', s).strip() if ignore_ws else s
        cur_hash = hashlib.sha256(canon(content).encode('utf-8')).hexdigest()
        row = cur.execute('SELECT content, hash, revision FROM "%s" WHERE k=?' % table, (key,)).fetchone()

        if row is None:
            cur.execute('INSERT INTO "%s" (k, content, hash, revision) VALUES (?,?,?,1)' % table, (key, content, cur_hash))
            conn.commit()
            return {'success': True, 'changed': False, 'firstSeen': True, 'key': key, 'currentHash': cur_hash, 'revision': 1, 'currentLength': len(content), 'message': 'Baseline snapshot stored; no previous version to compare.'}

        prev_content, prev_hash, rev = row[0] or '', row[1] or '', int(row[2] or 1)
        if prev_hash == cur_hash:
            cur.execute('UPDATE "%s" SET updated=datetime(\'now\') WHERE k=?' % table, (key,))
            conn.commit()
            return {'success': True, 'changed': False, 'firstSeen': False, 'key': key, 'currentHash': cur_hash, 'revision': rev, 'message': 'No change since last run.'}

        prev_lines = prev_content.splitlines()
        cur_lines = content.splitlines()
        diff_lines = list(difflib.unified_diff(prev_lines, cur_lines, fromfile='previous', tofile='current', lineterm='', n=2))
        added = [l[1:] for l in diff_lines if l.startswith('+') and not l.startswith('+++')]
        removed = [l[1:] for l in diff_lines if l.startswith('-') and not l.startswith('---')]
        diff_text = '\n'.join(diff_lines)
        new_rev = rev + 1
        cur.execute('UPDATE "%s" SET content=?, hash=?, revision=?, updated=datetime(\'now\') WHERE k=?' % table, (content, cur_hash, new_rev, key))
        conn.commit()
        CAP = 8000
        return {'success': True, 'changed': True, 'firstSeen': False, 'key': key, 'previousHash': prev_hash, 'currentHash': cur_hash, 'revision': new_rev, 'addedCount': len(added), 'removedCount': len(removed), 'added': added[:300], 'removed': removed[:300], 'diff': diff_text[:CAP], 'diffTruncated': len(diff_text) > CAP, 'previousContent': prev_content[:4000], 'currentContent': content[:4000], 'previousLength': len(prev_content), 'currentLength': len(content), 'message': 'Content changed: %d line(s) added, %d removed.' % (len(added), len(removed))}
    except Exception as e:
        return {'success': False, 'error': str(e)}
    finally:
        conn.close()

def execute(params):
    """Fetch and parse an RSS or Atom feed into a clean list of items.

    Pass `url` (the feed URL — it is fetched) and/or `content` (raw feed XML to
    parse directly). Returns { items: [{title, link, summary, published, id}],
    count, feedTitle }. Handles RSS 2.0, RDF/RSS 1.0, and Atom; strips HTML from
    summaries. Pair with db_store (key="link" or "id") to keep only new items.
    """
    import re, json

    url = str(params.get('url') or '').strip()
    content = params.get('content')
    try:
        limit = int(params.get('limit') or 50)
    except Exception:
        limit = 50

    xml_text = content if (isinstance(content, str) and content.strip()) else None
    if not xml_text and url:
        headers = {'User-Agent': 'Mozilla/5.0 (compatible; AutomationFeedReader/1.0)'}
        try:
            import urllib.request
            req = urllib.request.Request(url, headers=headers)
            with urllib.request.urlopen(req, timeout=20) as r:
                xml_text = r.read().decode('utf-8', 'replace')
        except Exception as e1:
            try:
                import requests
                xml_text = requests.get(url, headers=headers, timeout=20).text
            except Exception as e2:
                return {'success': False, 'error': 'fetch failed: ' + str(e2 or e1)}
    if not xml_text:
        return {'success': False, 'error': 'provide "url" (the feed to fetch) or "content" (raw feed XML)'}

    import xml.etree.ElementTree as ET
    xml_text = xml_text.lstrip('﻿').strip()
    try:
        root = ET.fromstring(xml_text)
    except Exception:
        cleaned = re.sub(r'&(?!(amp|lt|gt|quot|apos|#\d+|#x[0-9a-fA-F]+);)', '&amp;', xml_text)
        try:
            root = ET.fromstring(cleaned)
        except Exception as e:
            return {'success': False, 'error': 'XML parse failed: ' + str(e)}

    def ln(tag):
        return tag.rsplit('}', 1)[-1].lower() if isinstance(tag, str) else ''
    def child_text(el, names):
        for ch in el:
            if ln(ch.tag) in names:
                t = ''.join(ch.itertext()).strip() if list(ch) else (ch.text or '').strip()
                if t:
                    return t
        return ''
    def child_link(el):
        alt = first = ''
        for ch in el:
            if ln(ch.tag) == 'link':
                href = ch.get('href')
                if href:
                    rel = (ch.get('rel') or 'alternate').lower()
                    if rel == 'alternate' and not alt:
                        alt = href
                    if not first:
                        first = href
                elif (ch.text or '').strip() and not first:
                    first = ch.text.strip()
        return alt or first

    def strip_html(s):
        return re.sub(r'\s+', ' ', re.sub(r'<[^>]+>', ' ', s or '')).strip()

    items = []
    for el in root.iter():
        if ln(el.tag) in ('item', 'entry'):
            title = child_text(el, ('title',))
            link = child_link(el)
            guid = child_text(el, ('guid', 'id'))
            summary = strip_html(child_text(el, ('description', 'summary', 'encoded', 'content')))
            published = child_text(el, ('pubdate', 'published', 'updated', 'date'))
            if title or link or guid:
                items.append({
                    'title': title, 'link': link or guid, 'summary': summary[:1000],
                    'published': published, 'id': guid or link,
                })
            if len(items) >= limit:
                break
    feed_title = ''
    for el in root.iter():
        if ln(el.tag) in ('channel', 'feed'):
            feed_title = child_text(el, ('title',))
            break
    return {'success': True, 'count': len(items), 'feedTitle': feed_title, 'items': items}

def execute(params):
    """Send a workspace file to Telegram (sendDocument), Slack (files.upload) or any HTTP endpoint (multipart)."""
    import os, requests

    to = (params.get('destination') or params.get('to') or 'telegram').strip().lower()
    caption = params.get('caption')

    # Locate the file: explicit path, else the newest file in /workspace/artifacts/.
    path = (params.get('path') or '').strip()
    if not path:
        d = '/workspace/artifacts'
        if os.path.isdir(d):
            cands = [os.path.join(d, f) for f in os.listdir(d) if os.path.isfile(os.path.join(d, f)) and not f.startswith('.')]
            if cands:
                path = max(cands, key=os.path.getmtime)
    if not path:
        return {'success': False, 'error': 'no file to send — set a path or produce a file upstream (e.g. create_pdf)'}
    if not os.path.isabs(path):
        path = os.path.join('/workspace', path)
    if not os.path.isfile(path):
        return {'success': False, 'error': f'no such file: {path}'}
    fname = os.path.basename(path)

    try:
        if to == 'telegram':
            token = (params.get('botToken') or '').strip()
            chat = (params.get('chatId') or '').strip()
            if not token or not chat:
                return {'success': False, 'error': 'telegram needs botToken and chatId'}
            data = {'chat_id': chat}
            if caption:
                data['caption'] = str(caption)[:1024]
            with open(path, 'rb') as fh:
                r = requests.post(f'https://api.telegram.org/bot{token}/sendDocument', data=data, files={'document': (fname, fh)}, timeout=120)
            ok = r.ok and r.json().get('ok')
            return {'success': bool(ok), 'channel': 'telegram', 'file': fname} if ok else {'success': False, 'error': f'telegram sendDocument failed ({r.status_code}): {r.text[:200]}'}

        if to == 'slack':
            token = (params.get('botToken') or params.get('token') or '').strip()
            chan = (params.get('channel') or '').strip()
            if not token or not chan:
                return {'success': False, 'error': 'slack needs a bot token (xoxb-) and channel id'}
            data = {'channels': chan}
            if caption:
                data['initial_comment'] = str(caption)
            with open(path, 'rb') as fh:
                r = requests.post('https://slack.com/api/files.upload', headers={'Authorization': 'Bearer ' + token}, data=data, files={'file': (fname, fh)}, timeout=120)
            ok = r.ok and r.json().get('ok')
            return {'success': bool(ok), 'channel': 'slack', 'file': fname} if ok else {'success': False, 'error': f'slack files.upload failed: {r.text[:200]}'}

        if to == 'http':
            url = (params.get('url') or '').strip()
            if not url:
                return {'success': False, 'error': 'http needs a url'}
            field = params.get('field') or 'file'
            with open(path, 'rb') as fh:
                r = requests.post(url, files={field: (fname, fh)}, data=({'caption': str(caption)} if caption else {}), timeout=120)
            ok = 200 <= r.status_code < 300
            return {'success': ok, 'channel': 'http', 'file': fname, 'status': r.status_code} if ok else {'success': False, 'error': f'http upload failed ({r.status_code}): {r.text[:200]}'}

        return {'success': False, 'error': f'unknown destination: {to} (use telegram, slack, or http)'}
    except Exception as e:
        return {'success': False, 'error': str(e)}
